INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-math-boy-ai-mpxgw6ec',3,'math','boy','Grade 3 Math — BOY (Generated)',45,25,'ai','2026-06-03T02:49:20.072Z','{"id":"g3-math-boy-ai-mpxgw6ec","grade":3,"subject":"math","testType":"boy","title":"Grade 3 Math — BOY (Generated)","instructions":"Solve each question. Use diagrams where provided to help find the answer.","timeLimitMinutes":45,"calculatorAllowed":false,"source":"ai","passages":[],"questions":[{"id":"Q1","itemType":"single_choice","skill":"addition within 1000","difficulty":"easy","passageId":null,"questionText":"What is 467 + 358?","diagram":null,"options":["825","815","805","818"],"answer":0,"explanation":"Adding 467 and 358 gives 825.","points":1},{"id":"Q2","itemType":"single_choice","skill":"subtraction within 1000","difficulty":"easy","passageId":null,"questionText":"What is 932 - 487?","diagram":null,"options":["445","455","465","475"],"answer":1,"explanation":"Subtracting 487 from 932 gives 445.","points":1},{"id":"Q3","itemType":"single_choice","skill":"multiplication facts (0-10)","difficulty":"easy","passageId":null,"questionText":"What is 6 times 7?","diagram":null,"options":["42","36","48","49"],"answer":0,"explanation":"6 times 7 equals 42.","points":1},{"id":"Q4","itemType":"single_choice","skill":"division facts (0-10)","difficulty":"easy","passageId":null,"questionText":"What is 56 divided by 8?","diagram":null,"options":["7","6","8","9"],"answer":0,"explanation":"56 divided by 8 equals 7.","points":1},{"id":"Q5","itemType":"single_choice","skill":"fractions on a number line","difficulty":"medium","passageId":null,"questionText":"Which point on the number line shows the fraction 3/4?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.25,"point":0.75}},"options":["1/4","2/4","3/4","4/4"],"answer":2,"explanation":"The point at 0.75 corresponds to 3/4.","points":1},{"id":"Q6","itemType":"multi_select","skill":"identifying quadrilaterals","difficulty":"medium","passageId":null,"questionText":"Which of the following shapes are quadrilaterals?","diagram":null,"options":["Square","Triangle","Rectangle","Pentagon"],"answer":[0,2],"explanation":"Both squares and rectangles have four sides, making them quadrilaterals.","points":1},{"id":"Q7","itemType":"single_choice","skill":"telling time to the minute","difficulty":"medium","passageId":null,"questionText":"What time is shown on the clock?","diagram":{"type":"clock","params":{"hour":3,"minute":25}},"options":["3:05","3:15","3:25","3:35"],"answer":2,"explanation":"The clock shows 3:25.","points":1},{"id":"Q8","itemType":"single_choice","skill":"area of rectangles","difficulty":"medium","passageId":null,"questionText":"What is the area of a rectangle with a width of 4 units and a height of 5 units?","diagram":{"type":"rectangle","params":{"width":4,"height":5,"unit":"units","showGrid":true,"label":"Area"}},"options":["20 square units","18 square units","22 square units","24 square units"],"answer":0,"explanation":"Area is calculated as width × height, so 4 × 5 = 20 square units.","points":1},{"id":"Q9","itemType":"numeric_entry","skill":"rounding to the nearest ten","difficulty":"easy","passageId":null,"questionText":"Round 76 to the nearest ten.","diagram":null,"options":[],"answer":80,"explanation":"76 rounded to the nearest ten is 80.","points":1},{"id":"Q10","itemType":"single_choice","skill":"interpreting bar graphs","difficulty":"medium","passageId":null,"questionText":"Which category has the most items in the bar graph?","diagram":{"type":"bar_graph","params":{"title":"Number of Books","xLabel":"Category","yLabel":"Books","yMax":10,"yStep":2,"bars":[{"label":"Fiction","value":8},{"label":"Non-Fiction","value":5},{"label":"Comics","value":6},{"label":"Biography","value":9}]}},"options":["Fiction","Non-Fiction","Comics","Biography"],"answer":3,"explanation":"Biography has the highest bar, indicating the most items.","points":1},{"id":"Q11","itemType":"single_choice","skill":"measurement of length","difficulty":"easy","passageId":null,"questionText":"If a pencil is 12 cm long and a ruler is 30 cm long, how much longer is the ruler than the pencil?","diagram":null,"options":["18 cm","20 cm","22 cm","15 cm"],"answer":0,"explanation":"The ruler is 30 cm - 12 cm = 18 cm longer than the pencil.","points":1},{"id":"Q12","itemType":"single_choice","skill":"partitioning shapes","difficulty":"medium","passageId":null,"questionText":"How many equal parts are in a shape that is divided into fourths?","diagram":{"type":"fraction_circle","params":{"parts":4,"shaded":0}},"options":["2","3","4","5"],"answer":2,"explanation":"A shape divided into fourths has 4 equal parts.","points":1},{"id":"Q13","itemType":"single_choice","skill":"place value understanding","difficulty":"easy","passageId":null,"questionText":"What is the value of the digit 5 in the number 352?","diagram":null,"options":["5","50","500","5000"],"answer":1,"explanation":"The digit 5 is in the tens place, so its value is 50.","points":1},{"id":"Q14","itemType":"single_choice","skill":"simple word problems","difficulty":"medium","passageId":null,"questionText":"Sara has 5 apples. She buys 7 more. How many apples does she have in total?","diagram":null,"options":["10","11","12","13"],"answer":2,"explanation":"5 apples + 7 apples = 12 apples.","points":1},{"id":"Q15","itemType":"numeric_entry","skill":"elapsed time calculation","difficulty":"hard","passageId":null,"questionText":"If a movie starts at 1:45 PM and ends at 3:10 PM, how long is the movie?","diagram":null,"options":[],"answer":85,"explanation":"The movie lasts from 1:45 to 3:10, which is 1 hour and 25 minutes, or 85 minutes.","points":1},{"id":"Q16","itemType":"multi_select","skill":"properties of operations","difficulty":"hard","passageId":null,"questionText":"Which of the following equations show the commutative property of multiplication?","diagram":null,"options":["3 × 4 = 4 × 3","5 + 2 = 2 + 5","6 × 7 = 7 × 6","8 - 5 = 5 - 8"],"answer":[0,2],"explanation":"The commutative property states that changing the order of the factors doesn’t change the product, true for multiplication.","points":1},{"id":"Q17","itemType":"single_choice","skill":"understanding mass","difficulty":"medium","passageId":null,"questionText":"If a bag of rice weighs 2 kg and another weighs 3 kg, what is the total mass of the rice?","diagram":null,"options":["4 kg","5 kg","6 kg","7 kg"],"answer":1,"explanation":"2 kg + 3 kg = 5 kg.","points":1},{"id":"Q18","itemType":"single_choice","skill":"equivalent fractions","difficulty":"hard","passageId":null,"questionText":"Which fraction is equivalent to 1/2?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":2,"shaded":1,"label":"1/2"},{"parts":4,"shaded":2,"label":"Equivalent"}]}},"options":["2/4","1/3","2/3","3/4"],"answer":0,"explanation":"1/2 is equivalent to 2/4 because they represent the same portion of a whole.","points":1},{"id":"Q19","itemType":"single_choice","skill":"volume measurement","difficulty":"medium","passageId":null,"questionText":"A container holds 4 liters of water. If 1 liter is poured out, how much water remains?","diagram":null,"options":["2 liters","3 liters","4 liters","5 liters"],"answer":1,"explanation":"4 liters - 1 liter = 3 liters remaining.","points":1},{"id":"Q20","itemType":"single_choice","skill":"using picture graphs","difficulty":"medium","passageId":null,"questionText":"In the picture graph below, how many more apples are there than bananas?","diagram":{"type":"picture_graph","params":{"title":"Fruit Count","symbol":"🍎","unitValue":1,"rows":[{"label":"Apples","count":6},{"label":"Bananas","count":3}]}},"options":["1","2","3","4"],"answer":2,"explanation":"6 apples - 3 bananas = 3 more apples.","points":1},{"id":"Q21","itemType":"single_choice","skill":"understanding perimeter","difficulty":"hard","passageId":null,"questionText":"What is the perimeter of a square with side length 9 cm?","diagram":{"type":"rectangle","params":{"width":9,"height":9,"unit":"cm","showGrid":false,"label":"Square"}},"options":["36 cm","40 cm","32 cm","45 cm"],"answer":0,"explanation":"Perimeter of a square is 4 times the side length: 4 × 9 cm = 36 cm.","points":1},{"id":"Q22","itemType":"numeric_entry","skill":"place value and rounding","difficulty":"easy","passageId":null,"questionText":"Round 144 to the nearest hundred.","diagram":null,"options":[],"answer":100,"explanation":"144 rounded to the nearest hundred is 100.","points":1},{"id":"Q23","itemType":"single_choice","skill":"understanding picture graphs","difficulty":"medium","passageId":null,"questionText":"If each 🍎 symbol in the graph represents 2 apples, how many apples are there in total?","diagram":{"type":"picture_graph","params":{"title":"Apple Count","symbol":"🍎","unitValue":2,"rows":[{"label":"Apples","count":5}]}},"options":["10","8","12","14"],"answer":0,"explanation":"5 symbols × 2 apples each = 10 apples.","points":1},{"id":"Q24","itemType":"multi_select","skill":"solving multi-step word problems","difficulty":"hard","passageId":null,"questionText":"Maria has 12 candies. She buys 8 more and gives 5 to her friend. How many candies does she have now?","diagram":null,"options":["15","20","17","18"],"answer":[2],"explanation":"12 candies + 8 candies - 5 candies = 15 candies.","points":1},{"id":"Q25","itemType":"single_choice","skill":"understanding base ten blocks","difficulty":"medium","passageId":null,"questionText":"How many tens are in the number 230?","diagram":{"type":"base_ten","params":{"hundreds":2,"tens":3,"ones":0}},"options":["20","23","30","3"],"answer":3,"explanation":"There are 3 tens in 230.","points":1}]}');
INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-read-eog-ai-mpyhaue1',3,'reading','eog','Grade 3 Reading — EOG (Generated)',120,40,'ai','2026-06-03T19:49:09.403Z','{"id":"g3-read-eog-ai-mpyhaue1","grade":3,"subject":"reading","testType":"eog","title":"Grade 3 Reading — EOG (Generated)","instructions":"Read each passage carefully. Then answer the questions that follow. Choose the best answer for each question. Some questions may ask you to select more than one answer.","timeLimitMinutes":120,"calculatorAllowed":false,"source":"ai","passages":[{"id":"P1","title":"The Tale of the Brave Little Squirrel","genre":"fiction","lexile":"640L","text":"Part 1\n\nIn a quiet forest, there lived a little squirrel named Sammy. Sammy was curious and loved to explore new places. One sunny morning, Sammy decided to venture beyond the familiar oak trees.\n\nAs he ventured further, he encountered a wide river. Sammy had never crossed a river before, but he was determined to see what lay on the other side. He gathered some sticks and leaves to build a tiny raft.\n\nPart 2\n\nWith his raft ready, Sammy pushed it into the river and hopped on. The current was swift, but Sammy held on tight. Then, he spotted a family of ducks swimming nearby. They quacked in encouragement as Sammy paddled. Finally, Sammy reached the other side, feeling braver than ever. He discovered a beautiful meadow filled with colorful flowers."},{"id":"P2","title":"The Life of a Pond","genre":"informational","lexile":"680L","text":"Part 1\n\nPonds are small bodies of still water that can be found in many places. They are home to a variety of plants and animals. In the spring, frogs lay eggs in the pond, which hatch into tadpoles.\n\nPonds also have algae, which are tiny plants that float on the surface. Algae provide food for many small creatures, including insects and snails.\n\nPart 2\n\nAs the seasons change, so does the pond. In summer, the water warms up, and many animals become more active. Birds often visit ponds to drink and catch insects. In winter, some ponds may freeze over, but life continues beneath the ice."},{"id":"P3","title":"The Adventure of Emily the Explorer","genre":"fiction","lexile":"670L","text":"Part 1\n\nEmily loved going on adventures. One day, she decided to explore the mysterious cave at the edge of her village. She packed a small bag with a flashlight, some snacks, and a notebook.\n\nAs she entered the cave, Emily felt a rush of excitement. The walls were covered in sparkling crystals that glimmered in the flashlight''s beam.\n\nPart 2\n\nEmily carefully walked further into the cave, making notes of the interesting formations she saw. Suddenly, she heard a soft fluttering sound. It was a group of bats flying overhead. Emily watched in awe, knowing she was witnessing something special. Her adventure brought her a sense of wonder and discovery."},{"id":"P4","title":"The History of the Bicycle","genre":"informational","lexile":"700L","text":"Part 1\n\nThe bicycle is a popular form of transportation that has been around for over 200 years. It started as a simple wooden frame with two wheels, called a ''dandy horse.''\n\nIn the 19th century, bicycles evolved to include pedals and chains, making them easier to ride. This new design was called the ''penny-farthing,'' known for its large front wheel.\n\nPart 2\n\nAs time went on, bicycles became safer and more comfortable. The invention of the safety bicycle, with two wheels of equal size, allowed more people to enjoy cycling. Today, bicycles are used for recreation, exercise, and commuting."},{"id":"P5","title":"The Journey of a Raindrop","genre":"poetry","lexile":"650L","text":"Part 1\n\nFalling from the sky,\nA raindrop begins its ride,\nBouncing off the leaves,\nOn a journey far and wide.\n\nPart 2\n\nFlowing down the streams,\nJoining rivers swift and deep,\nTo the ocean''s arms,\nWhere it finally rests asleep."}],"questions":[{"id":"Q1","itemType":"single_choice","skill":"Key details","difficulty":"easy","passageId":"P1","questionText":"According to the text, what did Sammy do after he encountered the river?","diagram":null,"options":["He decided to go back home.","He built a tiny raft to cross it.","He asked the ducks for help.","He swam across the river."],"answer":1,"explanation":"The passage states that Sammy gathered sticks and leaves to build a tiny raft to cross the river.","points":1},{"id":"Q2","itemType":"single_choice","skill":"Character/sequence","difficulty":"medium","passageId":"P1","questionText":"Which word describes Sammy''s character?","diagram":null,"options":["Timid","Curious","Angry","Lazy"],"answer":1,"explanation":"The text describes Sammy as curious because he loves to explore new places.","points":1},{"id":"Q3","itemType":"single_choice","skill":"Main idea / theme","difficulty":"medium","passageId":"P1","questionText":"What is the main idea of the passage?","diagram":null,"options":["Sammy likes to build rafts.","Sammy''s adventure shows the importance of bravery and exploration.","The forest is a dangerous place for small animals.","Ducks are helpful animals."],"answer":1,"explanation":"The main theme is about bravery and exploration as demonstrated by Sammy''s actions.","points":1},{"id":"Q4","itemType":"single_choice","skill":"Evidence","difficulty":"medium","passageId":"P1","questionText":"Which detail from the text supports that Sammy was determined?","diagram":null,"options":["Sammy loved to explore new places.","Sammy gathered sticks and leaves to build a raft.","Sammy saw a family of ducks.","Sammy returned home safely."],"answer":1,"explanation":"Sammy''s action of building a raft shows his determination to cross the river.","points":1},{"id":"Q5","itemType":"single_choice","skill":"Vocabulary-in-context","difficulty":"easy","passageId":"P1","questionText":"What is the meaning of ''current'' in paragraph 2?","diagram":null,"options":["A type of fruit","The flow of water","The latest news","An electrical charge"],"answer":1,"explanation":"In the context of the passage, ''current'' refers to the flow of water in the river.","points":1},{"id":"Q6","itemType":"single_choice","skill":"Cross-part","difficulty":"hard","passageId":"P1","questionText":"What is one way Sammy at the beginning and Sammy at the end are alike?","diagram":null,"options":["He is unsure at both times.","He is afraid of the river at both times.","He is curious about new places.","He is accompanied by the ducks both times."],"answer":2,"explanation":"Sammy''s curiosity is evident both at the beginning when he decides to explore and at the end when he discovers the meadow.","points":1},{"id":"Q7","itemType":"single_choice","skill":"Figurative language","difficulty":"medium","passageId":"P1","questionText":"What is the meaning of the phrase ''feeling braver than ever'' in paragraph 4?","diagram":null,"options":["Sammy felt courageous and bold.","Sammy was tired from his journey.","Sammy wanted to go home.","Sammy was afraid of the ducks."],"answer":0,"explanation":"The phrase means that Sammy felt more courageous and bold after his adventure.","points":1},{"id":"Q8","itemType":"single_choice","skill":"Character/sequence","difficulty":"easy","passageId":"P1","questionText":"What did Sammy find on the other side of the river?","diagram":null,"options":["A dark forest","A rocky hill","A beautiful meadow","A deserted town"],"answer":2,"explanation":"The passage describes Sammy finding a beautiful meadow filled with colorful flowers.","points":1},{"id":"Q9","itemType":"single_choice","skill":"Key details","difficulty":"easy","passageId":"P2","questionText":"According to the text, what do frogs do in the spring at the pond?","diagram":null,"options":["They hibernate under the water.","They lay eggs in the pond.","They eat the algae.","They build nests."],"answer":1,"explanation":"The text states that frogs lay eggs in the pond during spring.","points":1},{"id":"Q10","itemType":"single_choice","skill":"Vocabulary-in-context","difficulty":"medium","passageId":"P2","questionText":"What is the meaning of ''algae'' in paragraph 2?","diagram":null,"options":["Large fish","Tiny plants that float on water","Water birds","Pond insects"],"answer":1,"explanation":"Algae are tiny plants that float on the surface of the pond, as described in the text.","points":1},{"id":"Q11","itemType":"single_choice","skill":"Main idea / theme","difficulty":"medium","passageId":"P2","questionText":"What is the main idea of the passage?","diagram":null,"options":["Ponds are important and support many forms of life.","Frogs are the most important animals in ponds.","Ponds freeze over completely in winter.","Birds do not visit ponds in summer."],"answer":0,"explanation":"The passage describes how ponds support various forms of life throughout the seasons.","points":1},{"id":"Q12","itemType":"single_choice","skill":"Text structure / connections","difficulty":"hard","passageId":"P2","questionText":"How does the author connect the ideas in paragraphs 1 and 2?","diagram":null,"options":["By explaining how algae are important for frogs.","By describing different animals that live in ponds.","By showing how ponds change with the seasons.","By comparing ponds to other bodies of water."],"answer":1,"explanation":"The paragraphs describe the variety of life in ponds, connecting frogs and algae as part of the ecosystem.","points":1},{"id":"Q13","itemType":"single_choice","skill":"Evidence","difficulty":"medium","passageId":"P2","questionText":"Which statement from the text supports the main idea?","diagram":null,"options":["Ponds are small bodies of still water.","Frogs lay eggs in the pond in spring.","Algae provide food for many small creatures.","Some ponds may freeze over in winter."],"answer":2,"explanation":"The statement about algae providing food supports the idea that ponds support various forms of life.","points":1},{"id":"Q14","itemType":"single_choice","skill":"Cross-part","difficulty":"hard","passageId":"P2","questionText":"What is one way the pond changes from summer to winter?","diagram":null,"options":["The algae disappears completely.","The pond becomes deeper in winter.","The pond may freeze over, but life continues beneath the ice.","Birds stop visiting the pond in winter."],"answer":2,"explanation":"The text explains that ponds may freeze over in winter but life continues beneath the ice.","points":1},{"id":"Q15","itemType":"single_choice","skill":"Character/sequence","difficulty":"easy","passageId":"P2","questionText":"What happens to tadpoles after they hatch?","diagram":null,"options":["They remain as tadpoles forever.","They grow into frogs.","They leave the pond immediately.","They turn into algae."],"answer":1,"explanation":"Tadpoles grow into frogs, completing their lifecycle.","points":1},{"id":"Q16","itemType":"single_choice","skill":"Key details","difficulty":"medium","passageId":"P2","questionText":"What do birds often do at ponds in summer?","diagram":null,"options":["Lay eggs","Catch insects","Build nests","Swim in the water"],"answer":1,"explanation":"The passage states that birds visit ponds to catch insects in the summer.","points":1},{"id":"Q17","itemType":"single_choice","skill":"Key details","difficulty":"easy","passageId":"P3","questionText":"According to the text, what did Emily bring with her into the cave?","diagram":null,"options":["A ladder","A camera","A flashlight and snacks","A friend"],"answer":2,"explanation":"Emily brought a flashlight, some snacks, and a notebook into the cave.","points":1},{"id":"Q18","itemType":"single_choice","skill":"Character/sequence","difficulty":"medium","passageId":"P3","questionText":"Which word describes Emily''s feelings as she enters the cave?","diagram":null,"options":["Afraid","Excited","Bored","Confused"],"answer":1,"explanation":"Emily felt a rush of excitement as she entered the cave, as described in the passage.","points":1},{"id":"Q19","itemType":"single_choice","skill":"Main idea / theme","difficulty":"medium","passageId":"P3","questionText":"What is the main idea of the passage?","diagram":null,"options":["Caves are dark and dangerous places.","Emily''s adventure shows her curiosity and desire to explore.","Bats are fascinating animals.","Emily found hidden treasure in the cave."],"answer":1,"explanation":"The passage highlights Emily''s curiosity and her adventurous spirit in exploring the cave.","points":1},{"id":"Q20","itemType":"single_choice","skill":"Evidence","difficulty":"medium","passageId":"P3","questionText":"Which detail from the text supports Emily''s sense of wonder?","diagram":null,"options":["Emily packed a small bag with snacks.","The walls were covered in sparkling crystals.","Emily heard a soft fluttering sound.","Emily made notes of the formations."],"answer":1,"explanation":"The sparkling crystals in the cave contribute to Emily''s sense of wonder and amazement.","points":1},{"id":"Q21","itemType":"single_choice","skill":"Vocabulary-in-context","difficulty":"easy","passageId":"P3","questionText":"What is the meaning of ''formation'' in paragraph 4?","diagram":null,"options":["A group of people","A dance move","A shape or structure","A type of food"],"answer":2,"explanation":"In the context of the passage, ''formation'' refers to the shapes or structures within the cave.","points":1},{"id":"Q22","itemType":"single_choice","skill":"Figurative language","difficulty":"medium","passageId":"P3","questionText":"What is the meaning of the phrase ''rush of excitement'' in paragraph 2?","diagram":null,"options":["A quick run","A feeling of great enthusiasm","A sudden wind","A large crowd"],"answer":1,"explanation":"The phrase ''rush of excitement'' means a feeling of great enthusiasm or eagerness.","points":1},{"id":"Q23","itemType":"single_choice","skill":"Cross-part","difficulty":"hard","passageId":"P3","questionText":"How does Emily''s attitude towards the cave change from Part 1 to Part 2?","diagram":null,"options":["From fear to boredom","From excitement to disappointment","From curiosity to wonder","From confusion to understanding"],"answer":2,"explanation":"Emily''s attitude evolves from initial curiosity to a deeper sense of wonder as she explores the cave.","points":1},{"id":"Q24","itemType":"single_choice","skill":"Key details","difficulty":"easy","passageId":"P3","questionText":"What did Emily see flying overhead in the cave?","diagram":null,"options":["Birds","Butterflies","Bats","Insects"],"answer":2,"explanation":"Emily saw a group of bats flying overhead in the cave.","points":1},{"id":"Q25","itemType":"single_choice","skill":"Key details","difficulty":"easy","passageId":"P4","questionText":"According to the text, what was the ''dandy horse''?","diagram":null,"options":["A type of horse","A wooden frame with two wheels","A bicycle with pedals","A racing car"],"answer":1,"explanation":"The ''dandy horse'' was a simple wooden frame with two wheels, as described in the passage.","points":1},{"id":"Q26","itemType":"single_choice","skill":"Vocabulary-in-context","difficulty":"medium","passageId":"P4","questionText":"What is the meaning of ''evolved'' in paragraph 2?","diagram":null,"options":["Stopped working","Changed and developed","Went out of style","Became more expensive"],"answer":1,"explanation":"In this context, ''evolved'' means that bicycles changed and developed over time.","points":1},{"id":"Q27","itemType":"single_choice","skill":"Main idea / theme","difficulty":"medium","passageId":"P4","questionText":"What is the main idea of the passage?","diagram":null,"options":["Bicycles have always been the same.","The design of bicycles has improved over time.","Bicycles are only used for racing.","The penny-farthing is the most popular bicycle."],"answer":1,"explanation":"The passage discusses how bicycles have improved and evolved over time.","points":1},{"id":"Q28","itemType":"single_choice","skill":"Text structure / connections","difficulty":"hard","passageId":"P4","questionText":"What is the connection between paragraphs 1 and 2?","diagram":null,"options":["They describe the safety features of bicycles.","They explain how bicycles became faster.","They show the changes in bicycle design over time.","They compare bicycles to other forms of transportation."],"answer":2,"explanation":"The paragraphs show the progression and changes in bicycle design from simple to more advanced forms.","points":1},{"id":"Q29","itemType":"single_choice","skill":"Evidence","difficulty":"medium","passageId":"P4","questionText":"Which detail from the text supports the idea that bicycles became more comfortable?","diagram":null,"options":["Bicycles were called ''dandy horses''.","The penny-farthing had a large front wheel.","The safety bicycle had two wheels of equal size.","Bicycles were used for commuting."],"answer":2,"explanation":"The introduction of the safety bicycle with equal-sized wheels made bicycles more comfortable.","points":1},{"id":"Q30","itemType":"single_choice","skill":"Cross-part","difficulty":"hard","passageId":"P4","questionText":"What is one way the ''dandy horse'' and the ''safety bicycle'' are alike?","diagram":null,"options":["Both had pedals.","Both were made of wood.","Both had two wheels.","Both were used for racing."],"answer":2,"explanation":"Both the ''dandy horse'' and the ''safety bicycle'' had two wheels, although the designs were different.","points":1},{"id":"Q31","itemType":"single_choice","skill":"Character/sequence","difficulty":"easy","passageId":"P4","questionText":"What step follows the invention of pedals and chains on bicycles?","diagram":null,"options":["The creation of the ''dandy horse''","The use of bicycles for racing","The development of the penny-farthing","The invention of the bicycle helmet"],"answer":2,"explanation":"After the invention of pedals and chains, the penny-farthing with its large front wheel was developed.","points":1},{"id":"Q32","itemType":"single_choice","skill":"Key details","difficulty":"easy","passageId":"P5","questionText":"According to the poem, where does the raindrop rest?","diagram":null,"options":["In a cloud","On a leaf","In the ocean","In a pond"],"answer":2,"explanation":"The poem states that the raindrop finally rests in the ocean.","points":1},{"id":"Q33","itemType":"single_choice","skill":"Vocabulary-in-context","difficulty":"medium","passageId":"P5","questionText":"What is the meaning of ''journey'' in Part 1?","diagram":null,"options":["A short walk","A long trip","A quick ride","A lazy afternoon"],"answer":1,"explanation":"In the poem, ''journey'' refers to the raindrop''s long trip from the sky to the ocean.","points":1},{"id":"Q34","itemType":"single_choice","skill":"Main idea / theme","difficulty":"medium","passageId":"P5","questionText":"What is the main idea of the poem?","diagram":null,"options":["Raindrops travel a short distance.","Raindrops have an important role in nature.","Raindrops stay on leaves forever.","Raindrops are only found in rivers."],"answer":1,"explanation":"The poem describes the journey of a raindrop and its role in the water cycle.","points":1},{"id":"Q35","itemType":"single_choice","skill":"Figurative language","difficulty":"medium","passageId":"P5","questionText":"What is the meaning of the phrase ''bouncing off the leaves'' in Part 1?","diagram":null,"options":["The raindrop is playing with the leaves.","The raindrop is moving quickly from leaf to leaf.","The raindrop is stuck on the leaves.","The raindrop is absorbed by the leaves."],"answer":1,"explanation":"The phrase suggests movement and the raindrop''s journey through nature.","points":1},{"id":"Q36","itemType":"single_choice","skill":"Text structure / connections","difficulty":"hard","passageId":"P5","questionText":"How does the author connect the ideas in Parts 1 and 2 of the poem?","diagram":null,"options":["By showing the raindrop''s journey from sky to ocean.","By comparing raindrops to other weather elements.","By describing the raindrop''s interaction with animals.","By explaining the raindrop''s cycle back to the sky."],"answer":0,"explanation":"The poem connects the journey of a raindrop from sky to ocean, illustrating its path.","points":1},{"id":"Q37","itemType":"single_choice","skill":"Evidence","difficulty":"medium","passageId":"P5","questionText":"Which line from the poem supports the idea that the raindrop travels far?","diagram":null,"options":["A raindrop begins its ride,","Bouncing off the leaves,","On a journey far and wide.","Where it finally rests asleep."],"answer":2,"explanation":"The line ''On a journey far and wide'' supports the idea of the raindrop''s extensive travel.","points":1},{"id":"Q38","itemType":"single_choice","skill":"Cross-part","difficulty":"hard","passageId":"P5","questionText":"What is one way the raindrop''s journey in Part 1 is different from Part 2?","diagram":null,"options":["Part 1 focuses on the raindrop''s descent, while Part 2 describes its rest.","Part 1 describes the raindrop in the ocean, while Part 2 describes it in the sky.","Part 1 shows the raindrop''s interaction with animals, while Part 2 shows its journey through plants.","Part 1 is about the raindrop''s evaporation, while Part 2 is about its condensation."],"answer":0,"explanation":"Part 1 focuses on the raindrop''s movement and journey, while Part 2 concludes with its rest in the ocean.","points":1},{"id":"Q39","itemType":"single_choice","skill":"Character/sequence","difficulty":"medium","passageId":"P5","questionText":"What follows the raindrop flowing down the streams?","diagram":null,"options":["It falls from the sky again.","It joins rivers swift and deep.","It rests on a leaf.","It becomes part of a cloud."],"answer":1,"explanation":"The poem describes the raindrop joining rivers after flowing down the streams.","points":1},{"id":"Q40","itemType":"single_choice","skill":"Key details","difficulty":"easy","passageId":"P5","questionText":"Where does the raindrop''s journey end?","diagram":null,"options":["In a cloud","In the ocean","On a mountain","In a river"],"answer":1,"explanation":"The poem concludes with the raindrop resting in the ocean.","points":1}]}');
INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-math-boy-1',3,'math','boy','Grade 3 Math — Beginning of Grade (BOG) Test 1',90,25,'curated','2026-06-02T00:00:00.000Z','{"id":"g3-math-boy-1","grade":3,"subject":"math","testType":"boy","title":"Grade 3 Math — Beginning of Grade (BOG) Test 1","instructions":"Read each question carefully. Choose the best answer. For type-in questions, write your number. For equation questions, find the number that goes in the box.","timeLimitMinutes":90,"calculatorAllowed":false,"source":"curated","passages":[],"questions":[{"id":"Q1","itemType":"single_choice","skill":"place_value","difficulty":"easy","passageId":null,"questionText":"What number do the base-ten blocks show?","diagram":{"type":"base_ten","params":{"hundreds":2,"tens":3,"ones":5}},"options":["253","235","532","325"],"answer":1,"explanation":"2 hundreds, 3 tens, and 5 ones make 200 + 30 + 5 = 235.","points":1},{"id":"Q2","itemType":"single_choice","skill":"place_value","difficulty":"easy","passageId":null,"questionText":"In the number 472, what is the value of the digit 7?","diagram":null,"options":["70","7","700","47"],"answer":0,"explanation":"The 7 is in the tens place, so its value is 7 tens = 70.","points":1},{"id":"Q3","itemType":"single_choice","skill":"addition","difficulty":"easy","passageId":null,"questionText":"What is 36 + 27?","diagram":null,"options":["62","53","63","73"],"answer":2,"explanation":"Add ones 6 + 7 = 13, write 3 and carry 1; tens 3 + 2 + 1 = 6. The sum is 63.","points":1},{"id":"Q4","itemType":"single_choice","skill":"subtraction","difficulty":"easy","passageId":null,"questionText":"What is 80 − 45?","diagram":null,"options":["125","35","45","25"],"answer":1,"explanation":"80 − 45 = 35.","points":1},{"id":"Q5","itemType":"single_choice","skill":"addition","difficulty":"medium","passageId":null,"questionText":"A store sold 248 apples on Monday and 175 apples on Tuesday. How many apples did the store sell in all?","diagram":null,"options":["313","423","523","413"],"answer":1,"explanation":"248 + 175 = 423 apples.","points":1},{"id":"Q6","itemType":"numeric_entry","skill":"subtraction","difficulty":"medium","passageId":null,"questionText":"A library had 320 books. Students borrowed 145 of them. How many books are left? Type your answer.","diagram":null,"options":[],"answer":175,"explanation":"320 − 145 = 175 books left.","points":1},{"id":"Q7","itemType":"single_choice","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"The dots below are arranged in equal rows. How many dots are there in all?","diagram":{"type":"array_dots","params":{"rows":3,"cols":5}},"options":["18","12","15","8"],"answer":2,"explanation":"3 rows of 5 dots is 3 × 5 = 15 dots.","points":1},{"id":"Q8","itemType":"single_choice","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"Which multiplication fact matches the array shown below?","diagram":{"type":"array_dots","params":{"rows":2,"cols":6}},"options":["3 × 6 = 18","2 × 5 = 10","2 × 4 = 8","2 × 6 = 12"],"answer":3,"explanation":"There are 2 rows with 6 dots each, so 2 × 6 = 12.","points":1},{"id":"Q9","itemType":"single_choice","skill":"multiplication","difficulty":"medium","passageId":null,"questionText":"There are 4 baskets. Each basket has 5 eggs. How many eggs are there in all?","diagram":{"type":"array_dots","params":{"rows":4,"cols":5}},"options":["20","25","16","9"],"answer":0,"explanation":"4 groups of 5 is 4 × 5 = 20 eggs.","points":1},{"id":"Q10","itemType":"numeric_entry","skill":"multiplication","difficulty":"medium","passageId":null,"questionText":"A box of crayons has 5 rows with 4 crayons in each row. How many crayons are in the box? Type your answer.","diagram":{"type":"array_dots","params":{"rows":5,"cols":4}},"options":[],"answer":20,"explanation":"5 rows of 4 is 5 × 4 = 20 crayons.","points":1},{"id":"Q11","itemType":"equation","skill":"addition","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"▢ + 24 = 40","answer":16,"options":[],"explanation":"40 − 24 = 16, so the blank is 16.","points":1},{"id":"Q12","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"What fraction of the bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":4,"shaded":1}},"options":["1/2","1/4","3/4","1/3"],"answer":1,"explanation":"The bar has 4 equal parts and 1 is shaded, so 1/4 is shaded.","points":1},{"id":"Q13","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"What fraction of the circle is shaded?","diagram":{"type":"fraction_circle","params":{"parts":3,"shaded":2}},"options":["1/3","2/2","3/2","2/3"],"answer":3,"explanation":"The circle has 3 equal parts and 2 are shaded, so 2/3 is shaded.","points":1},{"id":"Q14","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"What fraction does the point show on the number line?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.25,"point":0.5,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["4/4","1/4","2/4","3/4"],"answer":2,"explanation":"The number line is split into 4 equal parts. The point is on the 2nd mark, which is 2/4 (the same as one half).","points":1},{"id":"Q15","itemType":"single_choice","skill":"fractions","difficulty":"hard","passageId":null,"questionText":"Two same-size bars are split into equal parts. Which statement is true?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":3,"shaded":1,"label":"1/3"},{"parts":4,"shaded":1,"label":"1/4"}]}},"options":["1/3 is greater than 1/4","1/3 is equal to 1/4","1/4 is equal to 1/2","1/4 is greater than 1/3"],"answer":0,"explanation":"When a whole is split into fewer parts, each part is bigger. Thirds are bigger than fourths, so 1/3 is greater than 1/4.","points":1},{"id":"Q16","itemType":"single_choice","skill":"time","difficulty":"easy","passageId":null,"questionText":"What time does the clock show?","diagram":{"type":"clock","params":{"hour":4,"minute":30}},"options":["4:30","4:00","6:20","4:15"],"answer":0,"explanation":"The minute hand points to 6, which means 30 minutes, and the hour hand is halfway between 4 and 5. The time is 4:30.","points":1},{"id":"Q17","itemType":"single_choice","skill":"elapsed_time","difficulty":"hard","passageId":null,"questionText":"Class begins at 9:45 and lasts 30 minutes. What time does class end?","diagram":{"type":"clock","params":{"hour":9,"minute":45}},"options":["10:30","9:75","10:00","10:15"],"answer":3,"explanation":"Add 30 minutes to 9:45. From 9:45 to 10:00 is 15 minutes, then 15 more minutes makes 10:15.","points":1},{"id":"Q18","itemType":"single_choice","skill":"bar_graph","difficulty":"easy","passageId":null,"questionText":"The bar graph shows how many stickers each child has. How many stickers does Maya have?","diagram":{"type":"bar_graph","params":{"title":"Stickers","xLabel":"Child","yLabel":"Stickers","yMax":10,"yStep":2,"bars":[{"label":"Leo","value":4},{"label":"Maya","value":8},{"label":"Sam","value":6}]}},"options":["10","4","8","6"],"answer":2,"explanation":"Maya''s bar reaches 8 on the scale, so Maya has 8 stickers.","points":1},{"id":"Q19","itemType":"multi_select","skill":"multiplication","difficulty":"medium","passageId":null,"questionText":"Select all the number sentences that equal 12.","diagram":null,"options":["6 × 2","3 × 4","2 × 6","5 × 2"],"answer":[0,1,2],"explanation":"3 × 4 = 12, 2 × 6 = 12, and 6 × 2 = 12. But 5 × 2 = 10, so it is not correct.","points":1},{"id":"Q20","itemType":"numeric_entry","skill":"picture_graph","difficulty":"medium","passageId":null,"questionText":"Each star stands for 2 points. How many points were scored on Wednesday? Type your answer.","diagram":{"type":"picture_graph","params":{"title":"Points Scored","symbol":"⭐","unitValue":2,"rows":[{"label":"Mon","count":2},{"label":"Tue","count":4},{"label":"Wed","count":3}]}},"options":[],"answer":6,"explanation":"Wednesday has 3 star symbols and each stands for 2 points: 3 × 2 = 6 points.","points":1},{"id":"Q21","itemType":"multi_select","skill":"place_value","difficulty":"hard","passageId":null,"questionText":"Select all the numbers that are greater than 350 and less than 500.","diagram":null,"options":["362","305","480","515"],"answer":[0,2],"explanation":"362 and 480 are both greater than 350 and less than 500. 305 is too small and 515 is too big.","points":1},{"id":"Q22","itemType":"numeric_entry","skill":"perimeter","difficulty":"hard","passageId":null,"questionText":"What is the perimeter of the rectangle, in centimeters? Type your answer.","diagram":{"type":"rectangle","params":{"width":5,"height":3,"unit":"cm","showGrid":false,"label":"Card"}},"options":[],"answer":16,"explanation":"Perimeter = 5 + 3 + 5 + 3 = 16 cm. (Adding only 5 + 3 = 8 finds one side pair, not the whole perimeter.)","points":1},{"id":"Q23","itemType":"equation","skill":"subtraction","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"63 − ▢ = 38","answer":25,"options":[],"explanation":"63 − 38 = 25, so the blank is 25.","points":1},{"id":"Q24","itemType":"equation","skill":"multiplication","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"4 × ▢ = 28","answer":7,"options":[],"explanation":"28 ÷ 4 = 7, so the blank is 7.","points":1},{"id":"Q25","itemType":"equation","skill":"multiplication","difficulty":"hard","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"5 × 6 = ▢ + 10","answer":20,"options":[],"explanation":"5 × 6 = 30, and 30 = 20 + 10, so the blank is 20.","points":1}]}');
INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-math-eog-1',3,'math','eog','Grade 3 Math — EOG Practice Test 1',120,40,'curated','2026-06-02T00:00:00.000Z','{"id":"g3-math-eog-1","grade":3,"subject":"math","testType":"eog","title":"Grade 3 Math — EOG Practice Test 1","instructions":"Read each question carefully. Choose the best answer, type your answer in the box, or fill in the blank. You may not use a calculator.","timeLimitMinutes":120,"calculatorAllowed":false,"source":"curated","passages":[],"questions":[{"id":"Q1","itemType":"single_choice","skill":"MD.C.5 area-by-counting","difficulty":"easy","passageId":null,"questionText":"Each square is 1 square unit. The shape is made of equal rows of squares. What is the area of the shape?","diagram":{"type":"array_dots","params":{"rows":3,"cols":7}},"options":["24 square units","10 square units","21 square units","18 square units"],"answer":2,"explanation":"There are 3 rows of 7 unit squares, so the area is 3 × 7 = 21 square units.","points":1},{"id":"Q2","itemType":"single_choice","skill":"NF.A.1 fraction-of-a-whole","difficulty":"easy","passageId":null,"questionText":"What fraction of the circle is shaded?","diagram":{"type":"fraction_circle","params":{"parts":8,"shaded":3}},"options":["8/3","5/8","3/5","3/8"],"answer":3,"explanation":"3 of the 8 equal parts are shaded, so 3/8.","points":1},{"id":"Q3","itemType":"single_choice","skill":"NF.A.1 fraction-of-a-whole","difficulty":"easy","passageId":null,"questionText":"What fraction of the bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":3,"shaded":2}},"options":["1/3","3/2","2/5","2/3"],"answer":3,"explanation":"2 of the 3 equal parts are shaded, so 2/3.","points":1},{"id":"Q4","itemType":"single_choice","skill":"G.A.2 partition-equal-areas","difficulty":"easy","passageId":null,"questionText":"A rectangle is split into 4 equal parts. What fraction names the area of ONE part?","diagram":{"type":"fraction_bar","params":{"parts":4,"shaded":1}},"options":["1/2","1/4","2/4","4/1"],"answer":1,"explanation":"When a shape is split into 4 equal parts, each part is 1/4 of the whole area.","points":1},{"id":"Q5","itemType":"single_choice","skill":"OA.B.5 distributive-property","difficulty":"medium","passageId":null,"questionText":"Tara knows that 5 × 8 = 40. Which fact can help her find 6 × 8?","diagram":null,"options":["40 + 8 = 48","40 + 6 = 46","40 − 8 = 32","40 × 8 = 320"],"answer":0,"explanation":"6 × 8 is one more group of 8 than 5 × 8, so 40 + 8 = 48. This uses the distributive property: 6 × 8 = (5 × 8) + (1 × 8).","points":1},{"id":"Q6","itemType":"single_choice","skill":"OA.A.3 word-problem","difficulty":"medium","passageId":null,"questionText":"A teacher puts 9 chairs in each row and makes 7 rows. How many chairs are there in all?","diagram":null,"options":["72","56","16","63"],"answer":3,"explanation":"7 rows × 9 chairs = 63 chairs.","points":1},{"id":"Q7","itemType":"single_choice","skill":"OA.D.8 two-step-word-problem","difficulty":"hard","passageId":null,"questionText":"Marcus buys 6 packs of trading cards. Each pack has 8 cards. He gives 9 cards to a friend. How many cards does Marcus have left?","diagram":null,"options":["39","23","45","48"],"answer":0,"explanation":"First 6 × 8 = 48 cards. Then 48 − 9 = 39 cards left. The distractor 48 is the total before giving cards away.","points":1},{"id":"Q8","itemType":"single_choice","skill":"OA.D.8 two-step-word-problem","difficulty":"hard","passageId":null,"questionText":"A bakery had 7 boxes of 6 cupcakes. In the morning they sold 15 cupcakes. How many cupcakes are left?","diagram":null,"options":["57","27","13","42"],"answer":1,"explanation":"7 × 6 = 42 cupcakes to start. Then 42 − 15 = 27 cupcakes left.","points":1},{"id":"Q9","itemType":"single_choice","skill":"OA.D.9 arithmetic-pattern","difficulty":"medium","passageId":null,"questionText":"Look at the pattern: 4, 8, 12, 16, ___. What number comes next?","diagram":null,"options":["20","22","18","24"],"answer":0,"explanation":"The numbers increase by 4 each time. 16 + 4 = 20.","points":1},{"id":"Q10","itemType":"multi_select","skill":"OA.D.9 even-odd-reasoning","difficulty":"hard","passageId":null,"questionText":"Select ALL statements that are ALWAYS true.","diagram":null,"options":["The product of an even number and any whole number is even","Every multiple of 5 is odd","The product of two odd numbers is even","The sum of two odd numbers is even"],"answer":[0,3],"explanation":"Even × any whole number is even (4 × 3 = 12). Odd + odd is even (3 + 5 = 8). But odd × odd is odd (3 × 5 = 15), and multiples of 5 can be even (such as 10), so the last two are false.","points":1},{"id":"Q11","itemType":"multi_select","skill":"OA.C.7 equal-expressions","difficulty":"medium","passageId":null,"questionText":"Select ALL expressions that are equal to 36.","diagram":null,"options":["6 × 6","8 × 5","4 × 9","3 × 12"],"answer":[0,2,3],"explanation":"4 × 9 = 36, 6 × 6 = 36, and 3 × 12 = 36. But 8 × 5 = 40, which is not 36.","points":1},{"id":"Q12","itemType":"numeric_entry","skill":"OA.A.3 division-word-problem","difficulty":"medium","passageId":null,"questionText":"A coach divides 56 players into teams of 8 players each. How many teams are there?","diagram":null,"options":[],"answer":7,"explanation":"56 ÷ 8 = 7 teams.","points":1},{"id":"Q13","itemType":"equation","skill":"OA.A.4 multiplication","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"7 × ▢ = 63","answer":9,"options":[],"explanation":"63 ÷ 7 = 9, so 7 × 9 = 63.","points":1},{"id":"Q14","itemType":"equation","skill":"OA.A.4 division","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"48 ÷ ▢ = 6","answer":8,"options":[],"explanation":"48 ÷ 8 = 6, because 8 × 6 = 48.","points":1},{"id":"Q15","itemType":"equation","skill":"OA.A.4 addition","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"▢ + 38 = 65","answer":27,"options":[],"explanation":"65 − 38 = 27, so 27 + 38 = 65.","points":1},{"id":"Q16","itemType":"equation","skill":"OA.A.4 subtraction","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"84 − ▢ = 57","answer":27,"options":[],"explanation":"84 − 57 = 27, so 84 − 27 = 57.","points":1},{"id":"Q17","itemType":"equation","skill":"OA.D.8 multi-step","difficulty":"hard","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"6 × 8 = ▢ + 20","answer":28,"options":[],"explanation":"6 × 8 = 48. To make 48 = ▢ + 20, the blank must be 48 − 20 = 28.","points":1},{"id":"Q18","itemType":"equation","skill":"OA.A.4 division","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"▢ ÷ 9 = 4","answer":36,"options":[],"explanation":"If a number divided by 9 equals 4, then the number is 9 × 4 = 36.","points":1},{"id":"Q19","itemType":"single_choice","skill":"NBT.A.2 addition","difficulty":"easy","passageId":null,"questionText":"What is 365 + 247?","diagram":null,"options":["622","512","612","602"],"answer":2,"explanation":"365 + 247 = 612. Ones: 5+7=12; tens: 60+40+10=110; hundreds: 300+200+100=600; total 612.","points":1},{"id":"Q20","itemType":"single_choice","skill":"NBT.A.1 place-value","difficulty":"medium","passageId":null,"questionText":"What number do these base-ten blocks show?","diagram":{"type":"base_ten","params":{"hundreds":5,"tens":0,"ones":7}},"options":["570","57","507","5007"],"answer":2,"explanation":"5 hundreds, 0 tens, and 7 ones make 507.","points":1},{"id":"Q21","itemType":"single_choice","skill":"NBT.A.1 rounding-edge-case","difficulty":"hard","passageId":null,"questionText":"What is 549 rounded to the nearest hundred?","diagram":null,"options":["540","500","550","600"],"answer":1,"explanation":"To round to the nearest hundred, look at the tens digit. It is 4, so round DOWN: 549 rounds to 500. Do not be tricked by the 9 in the ones place.","points":1},{"id":"Q22","itemType":"numeric_entry","skill":"NBT.A.2 subtraction","difficulty":"medium","passageId":null,"questionText":"A school had 705 pencils. Students used 268 of them. How many pencils are left?","diagram":null,"options":[],"answer":437,"explanation":"705 − 268 = 437. Check: 437 + 268 = 705.","points":1},{"id":"Q23","itemType":"single_choice","skill":"NF.A.1 fraction-of-a-whole","difficulty":"easy","passageId":null,"questionText":"What fraction of the bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":6,"shaded":4}},"options":["6/4","4/6","4/10","2/6"],"answer":1,"explanation":"4 of the 6 equal parts are shaded, so 4/6.","points":1},{"id":"Q24","itemType":"single_choice","skill":"NF.A.2 fraction-on-number-line","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.125,"point":0.375,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["3/8","3/5","5/8","2/8"],"answer":0,"explanation":"The line from 0 to 1 is split into 8 equal parts. The point is at the third mark, which is 3/8.","points":1},{"id":"Q25","itemType":"single_choice","skill":"NF.A.3 fraction-comparison-number-line","difficulty":"hard","passageId":null,"questionText":"On a number line from 0 to 1, Point A is at 1/3 and Point B is at 1/4. Which statement is true?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.0833333,"point":0.3333333,"marks":[{"value":0,"label":"0"},{"value":0.25,"label":"B=1/4"},{"value":0.3333333,"label":"A=1/3"},{"value":1,"label":"1"}]}},"options":["1/3 is greater than 1/4","1/4 is greater than 1/3","1/4 is closer to 1","1/3 equals 1/4"],"answer":0,"explanation":"With numerator 1, the fraction with the SMALLER denominator is larger because the whole is cut into fewer, bigger pieces. Thirds are bigger than fourths, so 1/3 > 1/4, and A is to the right of B.","points":1},{"id":"Q26","itemType":"single_choice","skill":"NF.A.3 equivalent-fractions","difficulty":"medium","passageId":null,"questionText":"Which fraction is equivalent to 1/2?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":2,"shaded":1,"label":"A"},{"parts":6,"shaded":3,"label":"B"}]}},"options":["1/3","2/6","1/4","3/6"],"answer":3,"explanation":"Bar B shows 3 of 6 parts shaded, the same amount as 1 of 2. So 3/6 = 1/2.","points":1},{"id":"Q27","itemType":"single_choice","skill":"NF.A.1 fraction-of-a-whole","difficulty":"easy","passageId":null,"questionText":"What fraction of the circle is shaded?","diagram":{"type":"fraction_circle","params":{"parts":4,"shaded":3}},"options":["3/4","4/3","1/4","2/4"],"answer":0,"explanation":"3 of the 4 equal parts are shaded, so 3/4.","points":1},{"id":"Q28","itemType":"single_choice","skill":"NF.A.3 whole-number-as-fraction","difficulty":"hard","passageId":null,"questionText":"Which fraction is equal to the whole number 1?","diagram":{"type":"fraction_circle","params":{"parts":3,"shaded":3}},"options":["3/3","3/1","2/3","1/3"],"answer":0,"explanation":"When all 3 of 3 equal parts are shaded, the whole circle is filled. 3/3 = 1.","points":1},{"id":"Q29","itemType":"numeric_entry","skill":"NF.A.1 fraction-of-a-set","difficulty":"hard","passageId":null,"questionText":"There are 15 grapes on a plate. Maya eats 1/3 of them. How many grapes does Maya eat?","diagram":null,"options":[],"answer":5,"explanation":"To find 1/3 of 15, split into 3 equal groups: 15 ÷ 3 = 5 grapes.","points":1},{"id":"Q30","itemType":"multi_select","skill":"NF.A.3 equivalent-fractions","difficulty":"hard","passageId":null,"questionText":"Select ALL fractions that are equal to 1/2.","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":4,"shaded":2,"label":"A"},{"parts":8,"shaded":4,"label":"B"}]}},"options":["2/3","2/4","4/8","3/6"],"answer":[1,2,3],"explanation":"2/4, 3/6, and 4/8 all equal 1/2. But 2/3 is more than 1/2.","points":1},{"id":"Q31","itemType":"single_choice","skill":"NF.A.3 compare-same-numerator","difficulty":"medium","passageId":null,"questionText":"Greg ate 2/4 of a small pizza. Dana ate 2/8 of a same-size pizza. Who ate more pizza?","diagram":null,"options":["Cannot tell","They ate the same amount","Dana ate more","Greg ate more"],"answer":3,"explanation":"Both ate 2 pieces, but fourths are bigger than eighths, so 2/4 > 2/8. Greg ate more.","points":1},{"id":"Q32","itemType":"single_choice","skill":"NF.A.2 number-line-thirds","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.3333333,"point":0.6666667,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["1/3","3/3","2/3","2/6"],"answer":2,"explanation":"The line from 0 to 1 is split into 3 equal parts. The point is at the second mark, which is 2/3.","points":1},{"id":"Q33","itemType":"single_choice","skill":"MD.C.7 area","difficulty":"easy","passageId":null,"questionText":"What is the area of this rectangle?","diagram":{"type":"rectangle","params":{"width":8,"height":4,"unit":"cm","showGrid":true,"label":"Tile"}},"options":["16 square cm","24 square cm","32 square cm","12 square cm"],"answer":2,"explanation":"Area = length × width = 8 × 4 = 32 square cm.","points":1},{"id":"Q34","itemType":"single_choice","skill":"MD.D.8 area-vs-perimeter","difficulty":"hard","passageId":null,"questionText":"A rectangle is 9 feet long and 2 feet wide. What is its PERIMETER?","diagram":{"type":"rectangle","params":{"width":9,"height":2,"unit":"ft","showGrid":false,"label":"9 ft by 2 ft"}},"options":["18 ft","22 ft","20 ft","11 ft"],"answer":1,"explanation":"Perimeter = 9 + 2 + 9 + 2 = 22 ft. The distractor 18 is the AREA (9 × 2), a common area-vs-perimeter mix-up.","points":1},{"id":"Q35","itemType":"numeric_entry","skill":"MD.D.8 perimeter","difficulty":"medium","passageId":null,"questionText":"A square garden has sides that are each 6 meters long. What is the perimeter of the garden, in meters?","diagram":{"type":"shape","params":{"kind":"square","sideLabels":["6 m","6 m","6 m","6 m"]}},"options":[],"answer":24,"explanation":"A square has 4 equal sides. Perimeter = 6 + 6 + 6 + 6 = 24 meters.","points":1},{"id":"Q36","itemType":"single_choice","skill":"MD.A.1 elapsed-time-across-hour","difficulty":"hard","passageId":null,"questionText":"Recess starts at 10:40. It lasts 35 minutes. What time does recess end?","diagram":{"type":"clock","params":{"hour":10,"minute":40}},"options":["11:05","10:75","11:15","11:25"],"answer":2,"explanation":"10:40 + 35 minutes crosses the hour. 10:40 + 20 = 11:00, then 15 more minutes makes 11:15.","points":1},{"id":"Q37","itemType":"single_choice","skill":"MD.A.1 time-to-the-minute","difficulty":"easy","passageId":null,"questionText":"What time does the clock show?","diagram":{"type":"clock","params":{"hour":3,"minute":15}},"options":["3:03","9:15","15:03","3:15"],"answer":3,"explanation":"The hour hand is just past 3 and the minute hand points to 3, which is 15 minutes. The time is 3:15.","points":1},{"id":"Q38","itemType":"numeric_entry","skill":"MD.A.2 liquid-volume","difficulty":"medium","passageId":null,"questionText":"A pitcher holds 2 liters of juice. How many liters of juice are in 4 full pitchers? Type your answer.","diagram":null,"options":[],"answer":8,"explanation":"4 pitchers × 2 liters = 8 liters.","points":1},{"id":"Q39","itemType":"single_choice","skill":"MD.B.3 picture-graph","difficulty":"hard","passageId":null,"questionText":"Each ⭐ stands for 5 tickets sold. How many MORE tickets were sold on Friday than on Thursday?","diagram":{"type":"picture_graph","params":{"title":"Tickets Sold","symbol":"⭐","unitValue":5,"rows":[{"label":"Thu","count":3},{"label":"Fri","count":7}]}},"options":["15","20","4","35"],"answer":1,"explanation":"Friday: 7 × 5 = 35 tickets. Thursday: 3 × 5 = 15 tickets. 35 − 15 = 20 more tickets. The distractor 4 is the difference in stars, not tickets.","points":1},{"id":"Q40","itemType":"multi_select","skill":"G.A.1 quadrilaterals","difficulty":"medium","passageId":null,"questionText":"Select ALL shapes that are quadrilaterals.","diagram":null,"options":["Triangle","Rectangle","Trapezoid","Rhombus"],"answer":[1,2,3],"explanation":"Rectangles, rhombuses, and trapezoids all have exactly 4 sides, so they are quadrilaterals. A triangle has 3 sides.","points":1}]}');
INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-math-eog-2',3,'math','eog','Grade 3 Math — EOG Practice Test 2',120,40,'curated','2026-06-02T00:00:00.000Z','{"id":"g3-math-eog-2","grade":3,"subject":"math","testType":"eog","title":"Grade 3 Math — EOG Practice Test 2","instructions":"Read each question carefully. Choose the best answer, type your answer in the box, or fill in the blank to make the equation true. You may not use a calculator.","timeLimitMinutes":120,"calculatorAllowed":false,"source":"curated","passages":[],"questions":[{"id":"Q1","itemType":"single_choice","skill":"OA.A.1 multiplication","difficulty":"easy","passageId":null,"questionText":"The array shows buttons arranged in equal rows. How many buttons are there in all?","diagram":{"type":"array_dots","params":{"rows":4,"cols":6}},"options":["18","24","10","20"],"answer":1,"explanation":"4 rows of 6 buttons is 4 × 6 = 24.","points":1},{"id":"Q2","itemType":"single_choice","skill":"OA.C.7 multiplication-fact","difficulty":"easy","passageId":null,"questionText":"What is 7 × 9?","diagram":null,"options":["72","56","16","63"],"answer":3,"explanation":"7 × 9 = 63.","points":1},{"id":"Q3","itemType":"single_choice","skill":"OA.A.2 division-word-problem","difficulty":"easy","passageId":null,"questionText":"There are 48 crayons shared equally among 6 boxes. How many crayons go in each box?","diagram":null,"options":["6","9","7","8"],"answer":3,"explanation":"48 ÷ 6 = 8 crayons in each box.","points":1},{"id":"Q4","itemType":"equation","skill":"OA.C.7 division-fact","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"54 ÷ ▢ = 6","options":[],"answer":9,"explanation":"54 ÷ 9 = 6 because 9 × 6 = 54.","points":1},{"id":"Q5","itemType":"single_choice","skill":"OA.B.5 distributive-property","difficulty":"medium","passageId":null,"questionText":"Devon knows that 5 × 7 = 35. Which fact can help him find 6 × 7?","diagram":null,"options":["35 + 6 = 41","35 × 7 = 245","35 − 7 = 28","35 + 7 = 42"],"answer":3,"explanation":"6 × 7 is one more group of 7 than 5 × 7, so 35 + 7 = 42. This uses the distributive property: 6 × 7 = (5 × 7) + (1 × 7).","points":1},{"id":"Q6","itemType":"equation","skill":"OA.A.4 unknown-quotient","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"72 ÷ 8 = ▢","options":[],"answer":9,"explanation":"72 ÷ 8 = 9.","points":1},{"id":"Q7","itemType":"equation","skill":"OA.C.7 multiplication-fact","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"8 × ▢ = 56","options":[],"answer":7,"explanation":"56 ÷ 8 = 7.","points":1},{"id":"Q8","itemType":"single_choice","skill":"OA.D.8 two-step-word-problem","difficulty":"hard","passageId":null,"questionText":"Riley buys 7 packs of stickers. Each pack has 6 stickers. She gives 8 stickers to her brother. How many stickers does Riley have left?","diagram":null,"options":["34","42","48","50"],"answer":0,"explanation":"First 7 × 6 = 42 stickers. Then 42 − 8 = 34 stickers left. The distractor 42 is the total before giving any away.","points":1},{"id":"Q9","itemType":"numeric_entry","skill":"OA.D.8 two-step-word-problem","difficulty":"hard","passageId":null,"questionText":"A store has 5 shelves with 8 cans on each shelf. A worker adds 7 more cans. How many cans are there now?","diagram":null,"options":[],"answer":47,"explanation":"5 × 8 = 40 cans, then 40 + 7 = 47 cans.","points":1},{"id":"Q10","itemType":"single_choice","skill":"OA.D.9 arithmetic-pattern","difficulty":"medium","passageId":null,"questionText":"Look at the pattern: 6, 12, 18, 24, ___. What number comes next?","diagram":null,"options":["28","32","36","30"],"answer":3,"explanation":"The numbers increase by 6 each time. 24 + 6 = 30.","points":1},{"id":"Q11","itemType":"single_choice","skill":"OA.D.9 even-odd-reasoning","difficulty":"hard","passageId":null,"questionText":"Which statement is ALWAYS true?","diagram":null,"options":["The product of two odd numbers is odd","The sum of two even numbers is odd","Every multiple of 4 is odd","The sum of an odd number and an even number is even"],"answer":0,"explanation":"Odd × odd is always odd (e.g., 3 × 5 = 15). Two even numbers add to an even number, multiples of 4 are even, and odd + even is odd.","points":1},{"id":"Q12","itemType":"multi_select","skill":"OA.C.7 equal-expressions","difficulty":"medium","passageId":null,"questionText":"Select ALL expressions that are equal to 24.","diagram":null,"options":["5 × 5","2 × 12","4 × 6","3 × 8"],"answer":[1,2,3],"explanation":"4×6=24, 3×8=24, and 2×12=24. But 5×5=25, which is not 24.","points":1},{"id":"Q13","itemType":"equation","skill":"OA.A.4 unknown-factor","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"▢ × 4 = 28","options":[],"answer":7,"explanation":"28 ÷ 4 = 7, so 7 × 4 = 28.","points":1},{"id":"Q14","itemType":"numeric_entry","skill":"MD.A.2 liquid-volume","difficulty":"medium","passageId":null,"questionText":"A worker pours 24 liters of juice equally into 4 coolers. How many liters of juice are in each cooler?","diagram":null,"options":[],"answer":6,"explanation":"24 ÷ 4 = 6 liters in each cooler.","points":1},{"id":"Q15","itemType":"single_choice","skill":"NBT.A.2 addition","difficulty":"easy","passageId":null,"questionText":"What is 458 + 376?","diagram":null,"options":["824","834","724","734"],"answer":1,"explanation":"458 + 376 = 834. Ones: 8+6=14, tens: 50+70+10=130, hundreds: 400+300+100=800.","points":1},{"id":"Q16","itemType":"single_choice","skill":"NBT.A.1 place-value","difficulty":"medium","passageId":null,"questionText":"What number do these base-ten blocks show?","diagram":{"type":"base_ten","params":{"hundreds":4,"tens":0,"ones":9}},"options":["4009","490","409","49"],"answer":2,"explanation":"4 hundreds, 0 tens, and 9 ones make 409.","points":1},{"id":"Q17","itemType":"single_choice","skill":"NBT.A.1 rounding-edge-case","difficulty":"hard","passageId":null,"questionText":"What is 649 rounded to the nearest hundred?","diagram":null,"options":["650","640","600","700"],"answer":2,"explanation":"To round to the nearest hundred, look at the tens digit. It is 4, so round DOWN: 649 rounds to 600. Do not be tricked by the 9 in the ones place.","points":1},{"id":"Q18","itemType":"equation","skill":"NBT.A.2 subtraction","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"91 − ▢ = 64","options":[],"answer":27,"explanation":"91 − 64 = 27, so 91 − 27 = 64.","points":1},{"id":"Q19","itemType":"single_choice","skill":"NF.A.1 fraction-of-a-whole","difficulty":"easy","passageId":null,"questionText":"What fraction of the bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":8,"shaded":5}},"options":["8/5","5/10","5/8","3/8"],"answer":2,"explanation":"5 of the 8 equal parts are shaded, so 5/8.","points":1},{"id":"Q20","itemType":"single_choice","skill":"NF.A.2 fraction-on-number-line","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.25,"point":0.75,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["3/4","4/3","3/5","2/4"],"answer":0,"explanation":"The line from 0 to 1 is split into 4 equal parts. The point is at the third mark, which is 3/4.","points":1},{"id":"Q21","itemType":"single_choice","skill":"NF.A.3 fraction-comparison-number-line","difficulty":"hard","passageId":null,"questionText":"On a number line from 0 to 1, Point A is at 1/6 and Point B is at 1/3. Which statement is true?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.166667,"point":0.166667,"marks":[{"value":0,"label":"0"},{"value":0.166667,"label":"A=1/6"},{"value":0.333333,"label":"B=1/3"},{"value":1,"label":"1"}]}},"options":["1/6 is greater than 1/3","1/3 is greater than 1/6","1/6 equals 1/3","1/3 is closer to 0"],"answer":1,"explanation":"When the numerator is 1, the fraction with the SMALLER denominator is larger because the whole is cut into fewer, bigger pieces. Thirds are bigger than sixths, so 1/3 > 1/6, and B is to the right of A.","points":1},{"id":"Q22","itemType":"single_choice","skill":"NF.A.3 equivalent-fractions","difficulty":"medium","passageId":null,"questionText":"Which fraction is equivalent to 1/2?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":2,"shaded":1,"label":"A"},{"parts":8,"shaded":4,"label":"B"}]}},"options":["4/8","1/4","1/3","2/8"],"answer":0,"explanation":"Bar B shows 4 of 8 parts shaded, the same amount as 1 of 2. So 4/8 = 1/2.","points":1},{"id":"Q23","itemType":"multi_select","skill":"NF.A.3 fraction-comparison","difficulty":"hard","passageId":null,"questionText":"Select ALL comparisons that are TRUE.","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":6,"shaded":2,"label":"2/6"},{"parts":6,"shaded":5,"label":"5/6"}]}},"options":["5/6 > 2/6","1/2 > 1/6","1/3 > 1/2","4/4 = 1"],"answer":[0,1,3],"explanation":"5/6 > 2/6 (same denominator, bigger numerator), 4/4 = 1 (all parts shaded), and 1/2 > 1/6 (halves are bigger than sixths). But 1/3 < 1/2, so that one is false.","points":1},{"id":"Q24","itemType":"single_choice","skill":"NF.A.1 fraction-of-a-whole","difficulty":"easy","passageId":null,"questionText":"What fraction of the circle is shaded?","diagram":{"type":"fraction_circle","params":{"parts":6,"shaded":1}},"options":["1/5","6/1","1/6","5/6"],"answer":2,"explanation":"1 of the 6 equal parts is shaded, so 1/6.","points":1},{"id":"Q25","itemType":"single_choice","skill":"NF.A.3 whole-number-as-fraction","difficulty":"hard","passageId":null,"questionText":"Which fraction is equal to the whole number 1?","diagram":{"type":"fraction_circle","params":{"parts":4,"shaded":4}},"options":["3/4","4/4","4/1","1/4"],"answer":1,"explanation":"When all 4 of 4 equal parts are shaded, the whole circle is filled. 4/4 = 1.","points":1},{"id":"Q26","itemType":"numeric_entry","skill":"NF.A.1 fraction-of-a-set","difficulty":"medium","passageId":null,"questionText":"There are 18 grapes on a plate. Sam eats 1/3 of them. How many grapes does Sam eat?","diagram":null,"options":[],"answer":6,"explanation":"To find 1/3 of 18, split into 3 equal groups: 18 ÷ 3 = 6 grapes.","points":1},{"id":"Q27","itemType":"multi_select","skill":"NF.A.3 equivalent-fractions","difficulty":"hard","passageId":null,"questionText":"Select ALL fractions that are equal to 1/3.","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":3,"shaded":1,"label":"A"},{"parts":6,"shaded":2,"label":"B"}]}},"options":["3/9","2/6","4/6","2/3"],"answer":[0,1],"explanation":"2/6 = 1/3 and 3/9 = 1/3. But 2/3 and 4/6 both equal 2/3, which is more than 1/3.","points":1},{"id":"Q28","itemType":"single_choice","skill":"NF.A.3 compare-same-numerator","difficulty":"medium","passageId":null,"questionText":"Tomas ate 3/4 of a small sandwich. Nina ate 3/8 of a same-size sandwich. Who ate more?","diagram":null,"options":["They ate the same","Tomas ate more","Nina ate more","Cannot tell"],"answer":1,"explanation":"Both have 3 pieces, but fourths are bigger than eighths, so 3/4 > 3/8. Tomas ate more.","points":1},{"id":"Q29","itemType":"single_choice","skill":"NF.A.2 number-line-thirds","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.333333,"point":0.333333,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["2/3","1/2","1/3","3/3"],"answer":2,"explanation":"The line from 0 to 1 is split into 3 equal parts. The point is at the first mark, which is 1/3.","points":1},{"id":"Q30","itemType":"numeric_entry","skill":"NF.A.1 fraction-of-a-set","difficulty":"hard","passageId":null,"questionText":"There are 20 books on a shelf. One fifth (1/5) of them are red. How many books are red?","diagram":null,"options":[],"answer":4,"explanation":"To find 1/5 of 20, divide into 5 equal groups: 20 ÷ 5 = 4 red books.","points":1},{"id":"Q31","itemType":"single_choice","skill":"MD.C.7 area","difficulty":"easy","passageId":null,"questionText":"What is the area of this rectangle?","diagram":{"type":"rectangle","params":{"width":7,"height":5,"unit":"cm","showGrid":true,"label":"Tile"}},"options":["35 square cm","12 square cm","24 square cm","30 square cm"],"answer":0,"explanation":"Area = length × width = 7 × 5 = 35 square cm.","points":1},{"id":"Q32","itemType":"single_choice","skill":"MD.D.8 area-vs-perimeter","difficulty":"hard","passageId":null,"questionText":"A rectangle is 10 feet long and 3 feet wide. What is its PERIMETER?","diagram":{"type":"rectangle","params":{"width":10,"height":3,"unit":"ft","label":"10 ft by 3 ft"}},"options":["13 ft","23 ft","30 ft","26 ft"],"answer":3,"explanation":"Perimeter = 10 + 3 + 10 + 3 = 26 ft. The distractor 30 is the AREA (10 × 3), a common area-vs-perimeter mix-up.","points":1},{"id":"Q33","itemType":"numeric_entry","skill":"MD.D.8 perimeter","difficulty":"medium","passageId":null,"questionText":"A square rug has sides that are each 9 feet long. What is the perimeter of the rug, in feet?","diagram":{"type":"shape","params":{"kind":"square","sideLabels":["9 ft","9 ft","9 ft","9 ft"]}},"options":[],"answer":36,"explanation":"A square has 4 equal sides. Perimeter = 9 + 9 + 9 + 9 = 36 feet.","points":1},{"id":"Q34","itemType":"single_choice","skill":"MD.A.1 elapsed-time-across-hour","difficulty":"hard","passageId":null,"questionText":"Art class starts at 1:50. It lasts 40 minutes. What time does art class end?","diagram":{"type":"clock","params":{"hour":1,"minute":50}},"options":["2:10","2:40","1:90","2:30"],"answer":3,"explanation":"1:50 + 40 minutes crosses the hour. 1:50 + 10 = 2:00, then 30 more minutes makes 2:30.","points":1},{"id":"Q35","itemType":"single_choice","skill":"MD.A.1 time-to-the-minute","difficulty":"easy","passageId":null,"questionText":"What time does the clock show?","diagram":{"type":"clock","params":{"hour":8,"minute":45}},"options":["9:45","8:09","8:45","8:15"],"answer":2,"explanation":"The hour hand is between 8 and 9, and the minute hand points to 9, which is 45 minutes. The time is 8:45.","points":1},{"id":"Q36","itemType":"multi_select","skill":"MD.A.2 mass-volume","difficulty":"hard","passageId":null,"questionText":"Select ALL statements that are TRUE.","diagram":null,"options":["A pitcher holding 2 liters fills four 2-liter jugs","A 4-kilogram melon is 2 kilograms heavier than a 6-kilogram melon","6 bags of flour, each 3 kilograms, have a mass of 18 kilograms in all","Four 5-liter buckets hold 20 liters in all"],"answer":[2,3],"explanation":"6 × 3 = 18 kilograms (true) and 4 × 5 = 20 liters (true). One 2-liter pitcher cannot fill four 2-liter jugs (you would need 8 liters), and a 4-kilogram melon is lighter, not heavier, than a 6-kilogram one.","points":1},{"id":"Q37","itemType":"single_choice","skill":"MD.B.3 bar-graph","difficulty":"medium","passageId":null,"questionText":"The bar graph shows books read by four students. How many MORE books did Pam read than Leo?","diagram":{"type":"bar_graph","params":{"title":"Books Read","xLabel":"Student","yLabel":"Books","yMax":18,"yStep":3,"bars":[{"label":"Leo","value":6},{"label":"Mia","value":9},{"label":"Pam","value":15},{"label":"Ron","value":12}]}},"options":["21","9","6","3"],"answer":1,"explanation":"Pam read 15 books and Leo read 6. 15 − 6 = 9 more books.","points":1},{"id":"Q38","itemType":"single_choice","skill":"MD.B.3 picture-graph","difficulty":"hard","passageId":null,"questionText":"Each ⚽ stands for 4 goals scored. How many MORE goals did the Lions score than the Bears?","diagram":{"type":"picture_graph","params":{"title":"Goals Scored","symbol":"⚽","unitValue":4,"rows":[{"label":"Bears","count":2},{"label":"Lions","count":6}]}},"options":["16","4","8","24"],"answer":0,"explanation":"Lions: 6 × 4 = 24 goals. Bears: 2 × 4 = 8 goals. 24 − 8 = 16 more goals. The distractor 4 is the difference in symbols, not goals.","points":1},{"id":"Q39","itemType":"multi_select","skill":"G.A.1 quadrilaterals","difficulty":"medium","passageId":null,"questionText":"Select ALL shapes that are quadrilaterals.","diagram":null,"options":["Rhombus","Trapezoid","Square","Pentagon"],"answer":[0,1,2],"explanation":"Squares, rhombuses, and trapezoids all have exactly 4 sides, so they are quadrilaterals. A pentagon has 5 sides.","points":1},{"id":"Q40","itemType":"equation","skill":"OA.D.8 two-step-equation","difficulty":"hard","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"7 × 5 = ▢ + 15","options":[],"answer":20,"explanation":"7 × 5 = 35, and 35 = 20 + 15, so the blank is 20.","points":1}]}');
INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-math-eog-3',3,'math','eog','Grade 3 Math — EOG Practice Test 3',120,40,'curated','2026-06-02T00:00:00.000Z','{"id":"g3-math-eog-3","grade":3,"subject":"math","testType":"eog","title":"Grade 3 Math — EOG Practice Test 3","instructions":"Read each question carefully. Choose the best answer, type your answer in the box, or fill in the blank to make the equation true. You may not use a calculator.","timeLimitMinutes":120,"calculatorAllowed":false,"source":"curated","passages":[],"questions":[{"id":"Q1","itemType":"single_choice","skill":"OA.A.1 multiplication","difficulty":"easy","passageId":null,"questionText":"The array shows seashells arranged in equal rows. How many seashells are there in all?","diagram":{"type":"array_dots","params":{"rows":4,"cols":6}},"options":["10","24","18","20"],"answer":1,"explanation":"4 rows of 6 seashells is 4 × 6 = 24.","points":1},{"id":"Q2","itemType":"single_choice","skill":"OA.C.7 multiplication-fact","difficulty":"easy","passageId":null,"questionText":"What is 7 × 9?","diagram":null,"options":["16","56","63","72"],"answer":2,"explanation":"7 × 9 = 63.","points":1},{"id":"Q3","itemType":"single_choice","skill":"OA.A.2 division","difficulty":"easy","passageId":null,"questionText":"Mr. Lee shares 48 crayons equally among 6 students. How many crayons does each student get?","diagram":null,"options":["7","6","9","8"],"answer":3,"explanation":"48 ÷ 6 = 8 crayons for each student.","points":1},{"id":"Q4","itemType":"equation","skill":"OA.C.7 multiplication-fact","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"4 × ▢ = 32","answer":8,"options":[],"explanation":"32 ÷ 4 = 8, so 4 × 8 = 32.","points":1},{"id":"Q5","itemType":"single_choice","skill":"OA.B.5 distributive-property","difficulty":"medium","passageId":null,"questionText":"Nico knows that 4 × 7 = 28. Which fact can help him find 5 × 7?","diagram":null,"options":["28 + 5 = 33","28 × 7 = 196","28 + 7 = 35","28 − 7 = 21"],"answer":2,"explanation":"5 × 7 is one more group of 7 than 4 × 7, so 28 + 7 = 35. This uses the distributive property: 5 × 7 = (4 × 7) + (1 × 7).","points":1},{"id":"Q6","itemType":"equation","skill":"OA.C.7 multiplication-fact","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"▢ × 6 = 48","answer":8,"options":[],"explanation":"48 ÷ 6 = 8, so 8 × 6 = 48.","points":1},{"id":"Q7","itemType":"equation","skill":"OA.A.2 division-fact","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"54 ÷ ▢ = 6","answer":9,"options":[],"explanation":"54 ÷ 9 = 6 because 9 × 6 = 54.","points":1},{"id":"Q8","itemType":"single_choice","skill":"OA.D.8 two-step-word-problem","difficulty":"hard","passageId":null,"questionText":"Sofia buys 7 boxes of pencils. Each box has 8 pencils. She gives 12 pencils to her teacher. How many pencils does Sofia have left?","diagram":null,"options":["56","44","68","48"],"answer":1,"explanation":"First 7 × 8 = 56 pencils. Then 56 − 12 = 44 pencils left. The distractor 56 is the total before giving any away.","points":1},{"id":"Q9","itemType":"numeric_entry","skill":"OA.D.8 two-step-word-problem","difficulty":"hard","passageId":null,"questionText":"Devon has 5 bags with 7 oranges in each bag. He buys 9 more oranges. How many oranges does he have now? Write only the number.","diagram":null,"options":[],"answer":44,"explanation":"5 × 7 = 35 oranges, then 35 + 9 = 44 oranges.","points":1},{"id":"Q10","itemType":"equation","skill":"OA.A.4 missing-factor","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"6 × 4 = ▢ ÷ 2","answer":48,"options":[],"explanation":"6 × 4 = 24, and 48 ÷ 2 = 24, so the blank is 48.","points":1},{"id":"Q11","itemType":"multi_select","skill":"OA.D.9 even-odd-reasoning","difficulty":"hard","passageId":null,"questionText":"Select ALL numbers that are EVEN.","diagram":null,"options":["51","27","36","48"],"answer":[2,3],"explanation":"A number is even if its ones digit is 0, 2, 4, 6, or 8. 36 and 48 are even. 51 and 27 are odd.","points":1},{"id":"Q12","itemType":"multi_select","skill":"OA.C.7 equal-expressions","difficulty":"medium","passageId":null,"questionText":"Select ALL expressions that are equal to 24.","diagram":null,"options":["4 × 6","5 × 5","2 × 12","3 × 8"],"answer":[0,2,3],"explanation":"3×8=24, 4×6=24, and 2×12=24. But 5×5=25, which is not 24.","points":1},{"id":"Q13","itemType":"numeric_entry","skill":"OA.A.3 division-word-problem","difficulty":"medium","passageId":null,"questionText":"A coach divides 72 players into teams of 9 players each. How many teams are there? Write only the number.","diagram":null,"options":[],"answer":8,"explanation":"72 ÷ 9 = 8 teams.","points":1},{"id":"Q14","itemType":"equation","skill":"OA.D.8 equation-reasoning","difficulty":"hard","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"7 × 5 = ▢ + 15","answer":20,"options":[],"explanation":"7 × 5 = 35, and 35 = 20 + 15, so the blank is 20.","points":1},{"id":"Q15","itemType":"single_choice","skill":"NBT.A.2 addition","difficulty":"easy","passageId":null,"questionText":"What is 374 + 248?","diagram":null,"options":["632","612","622","522"],"answer":2,"explanation":"374 + 248 = 622. Ones: 4+8=12, tens: 70+40+10=120, hundreds: 300+200+100=600.","points":1},{"id":"Q16","itemType":"single_choice","skill":"NBT.A.2 subtraction","difficulty":"medium","passageId":null,"questionText":"A library had 612 books. Students borrowed 287 books. How many books are left?","diagram":null,"options":["425","315","435","325"],"answer":3,"explanation":"612 − 287 = 325. Check: 325 + 287 = 612.","points":1},{"id":"Q17","itemType":"single_choice","skill":"NBT.A.1 place-value","difficulty":"medium","passageId":null,"questionText":"What number do these base-ten blocks show?","diagram":{"type":"base_ten","params":{"hundreds":4,"tens":3,"ones":0}},"options":["430","43","403","4300"],"answer":0,"explanation":"4 hundreds, 3 tens, and 0 ones make 430.","points":1},{"id":"Q18","itemType":"single_choice","skill":"NBT.A.1 rounding-edge-case","difficulty":"hard","passageId":null,"questionText":"What is 748 rounded to the nearest hundred?","diagram":null,"options":["700","740","750","800"],"answer":0,"explanation":"To round to the nearest hundred, look at the tens digit. It is 4, so round DOWN: 748 rounds to 700. Do not be tricked by the 8 in the ones place.","points":1},{"id":"Q19","itemType":"numeric_entry","skill":"MD.B.3 data-table","difficulty":"medium","passageId":null,"questionText":"The table shows tickets sold each day. How many tickets were sold in all three days? Write only the number.","diagram":{"type":"data_table","params":{"headers":["Day","Tickets"],"rows":[["Friday","128"],["Saturday","215"],["Sunday","134"]]}},"options":[],"answer":477,"explanation":"128 + 215 + 134 = 477 tickets in all.","points":1},{"id":"Q20","itemType":"single_choice","skill":"NF.A.1 fraction-of-a-whole","difficulty":"easy","passageId":null,"questionText":"What fraction of the bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":8,"shaded":5}},"options":["5/8","3/8","8/5","5/3"],"answer":0,"explanation":"5 of the 8 equal parts are shaded, so 5/8.","points":1},{"id":"Q21","itemType":"single_choice","skill":"NF.A.2 fraction-on-number-line","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.2,"point":0.4,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["3/5","2/6","2/5","2/4"],"answer":2,"explanation":"The line from 0 to 1 is split into 5 equal parts. The point is at the second mark, which is 2/5.","points":1},{"id":"Q22","itemType":"single_choice","skill":"NF.A.3 fraction-comparison-number-line","difficulty":"hard","passageId":null,"questionText":"On a number line from 0 to 1, Point R is at 1/2 and Point S is at 1/3. Which statement is true?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.1666667,"point":0.5,"marks":[{"value":0,"label":"0"},{"value":0.3333333,"label":"S=1/3"},{"value":0.5,"label":"R=1/2"},{"value":1,"label":"1"}]}},"options":["1/3 is greater than 1/2","1/2 equals 1/3","1/2 is greater than 1/3","1/3 is closer to 1"],"answer":2,"explanation":"With a numerator of 1, the fraction with the SMALLER denominator is larger. Halves are bigger than thirds, so 1/2 > 1/3, and R is to the right of S.","points":1},{"id":"Q23","itemType":"single_choice","skill":"NF.A.3 equivalent-fractions","difficulty":"medium","passageId":null,"questionText":"Which fraction is equivalent to 1/2?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":2,"shaded":1,"label":"A"},{"parts":8,"shaded":4,"label":"B"}]}},"options":["4/8","1/4","3/8","2/8"],"answer":0,"explanation":"Bar B shows 4 of 8 parts shaded, the same amount as 1 of 2. So 4/8 = 1/2.","points":1},{"id":"Q24","itemType":"multi_select","skill":"NF.A.3 fraction-comparison","difficulty":"hard","passageId":null,"questionText":"Select ALL comparisons that are TRUE.","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":6,"shaded":2,"label":"2/6"},{"parts":6,"shaded":5,"label":"5/6"}]}},"options":["5/6 > 2/6","2/8 < 2/6","1/3 > 1/2","4/4 = 1"],"answer":[0,1,3],"explanation":"5/6 > 2/6 (same denominator, bigger numerator). 4/4 = 1 (all parts shaded). 2/8 < 2/6 (eighths are smaller than sixths). But 1/3 < 1/2, so that one is false.","points":1},{"id":"Q25","itemType":"single_choice","skill":"NF.A.1 fraction-of-a-whole","difficulty":"easy","passageId":null,"questionText":"What fraction of the circle is shaded?","diagram":{"type":"fraction_circle","params":{"parts":6,"shaded":1}},"options":["6/1","1/6","2/6","1/3"],"answer":1,"explanation":"1 of the 6 equal parts is shaded, so 1/6.","points":1},{"id":"Q26","itemType":"single_choice","skill":"NF.A.3 whole-number-as-fraction","difficulty":"hard","passageId":null,"questionText":"Which fraction is equal to the whole number 1?","diagram":{"type":"fraction_circle","params":{"parts":4,"shaded":4}},"options":["4/1","1/4","4/4","3/4"],"answer":2,"explanation":"When all 4 of 4 equal parts are shaded, the whole circle is filled. 4/4 = 1.","points":1},{"id":"Q27","itemType":"numeric_entry","skill":"NF.A.1 fraction-of-a-set","difficulty":"medium","passageId":null,"questionText":"There are 18 grapes on a plate. Maya eats 1/3 of them. How many grapes does Maya eat? Write only the number.","diagram":null,"options":[],"answer":6,"explanation":"To find 1/3 of 18, split into 3 equal groups: 18 ÷ 3 = 6 grapes.","points":1},{"id":"Q28","itemType":"multi_select","skill":"NF.A.3 equivalent-fractions","difficulty":"hard","passageId":null,"questionText":"Select ALL fractions that are equal to 1/3.","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":3,"shaded":1,"label":"A"},{"parts":6,"shaded":2,"label":"B"}]}},"options":["1/6","2/6","3/9","2/3"],"answer":[1,2],"explanation":"2/6 and 3/9 both equal 1/3. But 2/3 is more than 1/3, and 1/6 is less than 1/3.","points":1},{"id":"Q29","itemType":"single_choice","skill":"NF.A.3 compare-same-numerator","difficulty":"medium","passageId":null,"questionText":"Leo ate 3/4 of a small sandwich. Priya ate 3/8 of a same-size sandwich. Who ate more?","diagram":null,"options":["They ate the same","Leo ate more","Cannot tell","Priya ate more"],"answer":1,"explanation":"Both ate 3 pieces, but fourths are bigger than eighths, so 3/4 > 3/8. Leo ate more.","points":1},{"id":"Q30","itemType":"single_choice","skill":"NF.A.2 number-line-thirds","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.3333333,"point":0.3333333,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["2/6","1/3","3/3","2/3"],"answer":1,"explanation":"The line from 0 to 1 is split into 3 equal parts. The point is at the first mark, which is 1/3.","points":1},{"id":"Q31","itemType":"single_choice","skill":"MD.C.7 area","difficulty":"easy","passageId":null,"questionText":"What is the area of this rectangle?","diagram":{"type":"rectangle","params":{"width":7,"height":3,"unit":"cm","showGrid":true,"label":"Mat"}},"options":["21 square cm","10 square cm","24 square cm","20 square cm"],"answer":0,"explanation":"Area = length × width = 7 × 3 = 21 square cm.","points":1},{"id":"Q32","itemType":"single_choice","skill":"MD.D.8 area-vs-perimeter","difficulty":"hard","passageId":null,"questionText":"A rectangle is 8 feet long and 3 feet wide. What is its PERIMETER?","diagram":{"type":"rectangle","params":{"width":8,"height":3,"unit":"ft","label":"8 ft by 3 ft"}},"options":["24 ft","18 ft","11 ft","22 ft"],"answer":3,"explanation":"Perimeter = 8 + 3 + 8 + 3 = 22 ft. The distractor 24 is the AREA (8 × 3), a common area-vs-perimeter mix-up.","points":1},{"id":"Q33","itemType":"numeric_entry","skill":"MD.D.8 perimeter","difficulty":"medium","passageId":null,"questionText":"A square rug has sides that are each 7 feet long. What is the perimeter of the rug, in feet? Write only the number.","diagram":{"type":"shape","params":{"kind":"square","sideLabels":["7 ft","7 ft","7 ft","7 ft"]}},"options":[],"answer":28,"explanation":"A square has 4 equal sides. Perimeter = 7 + 7 + 7 + 7 = 28 feet.","points":1},{"id":"Q34","itemType":"single_choice","skill":"MD.A.1 elapsed-time-across-hour","difficulty":"hard","passageId":null,"questionText":"Music class starts at 9:50. It lasts 25 minutes. What time does music class end?","diagram":{"type":"clock","params":{"hour":9,"minute":50}},"options":["10:15","10:25","10:05","9:75"],"answer":0,"explanation":"9:50 + 25 minutes crosses the hour. 9:50 + 10 = 10:00, then 15 more minutes makes 10:15.","points":1},{"id":"Q35","itemType":"single_choice","skill":"MD.A.1 time-to-the-minute","difficulty":"easy","passageId":null,"questionText":"What time does the clock show?","diagram":{"type":"clock","params":{"hour":4,"minute":45}},"options":["4:05","9:04","4:09","4:45"],"answer":3,"explanation":"The hour hand is nearly at 5 and the minute hand points to 9, which is 45 minutes. The time is 4:45.","points":1},{"id":"Q36","itemType":"single_choice","skill":"MD.A.2 liquid-volume","difficulty":"medium","passageId":null,"questionText":"One bottle holds 2 liters of water. How many liters of water do 6 full bottles hold?","diagram":null,"options":["14 liters","8 liters","12 milliliters","12 liters"],"answer":3,"explanation":"6 bottles × 2 liters = 12 liters.","points":1},{"id":"Q37","itemType":"single_choice","skill":"MD.B.3 bar-graph","difficulty":"medium","passageId":null,"questionText":"The bar graph shows books read by four students. How many MORE books did Owen read than Mia?","diagram":{"type":"bar_graph","params":{"title":"Books Read","xLabel":"Student","yLabel":"Books","yMax":18,"yStep":3,"bars":[{"label":"Mia","value":6},{"label":"Owen","value":15},{"label":"Ben","value":9},{"label":"Zoe","value":12}]}},"options":["21","8","6","9"],"answer":3,"explanation":"Owen read 15 books and Mia read 6. 15 − 6 = 9 more books.","points":1},{"id":"Q38","itemType":"single_choice","skill":"MD.B.3 picture-graph","difficulty":"hard","passageId":null,"questionText":"Each ▲ stands for 4 cans collected. How many MORE cans were collected on Tuesday than on Monday?","diagram":{"type":"picture_graph","params":{"title":"Cans Collected","symbol":"▲","unitValue":4,"rows":[{"label":"Mon","count":3},{"label":"Tue","count":8}]}},"options":["5","20","12","32"],"answer":1,"explanation":"Tuesday: 8 × 4 = 32 cans. Monday: 3 × 4 = 12 cans. 32 − 12 = 20 more cans. The distractor 5 is the difference in symbols, not cans.","points":1},{"id":"Q39","itemType":"multi_select","skill":"G.A.1 quadrilaterals","difficulty":"medium","passageId":null,"questionText":"Select ALL shapes that are quadrilaterals.","diagram":null,"options":["Rhombus","Pentagon","Square","Trapezoid"],"answer":[0,2,3],"explanation":"Squares, rhombuses, and trapezoids all have exactly 4 sides, so they are quadrilaterals. A pentagon has 5 sides.","points":1},{"id":"Q40","itemType":"equation","skill":"NBT.A.2 missing-subtrahend","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"82 − ▢ = 47","answer":35,"options":[],"explanation":"82 − 47 = 35, so 82 − 35 = 47.","points":1}]}');
INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-math-eog-4',3,'math','eog','Grade 3 Math — EOG Practice Test 4',120,40,'curated','2026-06-02T00:00:00.000Z','{"id":"g3-math-eog-4","grade":3,"subject":"math","testType":"eog","title":"Grade 3 Math — EOG Practice Test 4","instructions":"Read each question carefully. Choose the best answer. For numeric entry questions, write only the number. For fill-in-the-blank equations, write the number that goes in the box.","timeLimitMinutes":120,"calculatorAllowed":false,"source":"curated","passages":[],"questions":[{"id":"Q1","itemType":"single_choice","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"The array below shows rows of buttons. Which multiplication fact does it show?","diagram":{"type":"array_dots","params":{"rows":4,"cols":6}},"options":["4 + 6 = 10","4 × 6 = 24","6 × 6 = 36","4 × 6 = 20"],"answer":1,"explanation":"There are 4 rows with 6 dots in each row. 4 × 6 = 24.","points":1},{"id":"Q2","itemType":"numeric_entry","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"What is 7 × 8? Write only the number.","diagram":null,"options":[],"answer":56,"explanation":"7 × 8 = 56.","points":1},{"id":"Q3","itemType":"single_choice","skill":"division","difficulty":"easy","passageId":null,"questionText":"What is 54 ÷ 6?","diagram":null,"options":["6","8","9","7"],"answer":2,"explanation":"6 × 9 = 54, so 54 ÷ 6 = 9.","points":1},{"id":"Q4","itemType":"single_choice","skill":"division","difficulty":"easy","passageId":null,"questionText":"Mr. Lopez has 32 crayons. He puts them into boxes of 8. How many boxes does he fill?","diagram":null,"options":["3","5","4","6"],"answer":2,"explanation":"32 ÷ 8 = 4 boxes.","points":1},{"id":"Q5","itemType":"equation","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"9 × ▢ = 63","options":[],"answer":7,"explanation":"63 ÷ 9 = 7, so 9 × 7 = 63.","points":1},{"id":"Q6","itemType":"single_choice","skill":"place_value","difficulty":"easy","passageId":null,"questionText":"Which number do these base-ten blocks show?","diagram":{"type":"base_ten","params":{"hundreds":3,"tens":6,"ones":4}},"options":["346","463","634","364"],"answer":3,"explanation":"3 hundreds, 6 tens, and 4 ones make 300 + 60 + 4 = 364.","points":1},{"id":"Q7","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"A bar is split into 3 equal parts. What fraction names ONE part?","diagram":{"type":"fraction_bar","params":{"parts":3,"shaded":1}},"options":["1/3","2/3","1/2","3/1"],"answer":0,"explanation":"When a whole is split into 3 equal parts, each part is 1/3 of the whole.","points":1},{"id":"Q8","itemType":"single_choice","skill":"rounding","difficulty":"easy","passageId":null,"questionText":"What is 86 rounded to the nearest ten?","diagram":null,"options":["86","90","100","80"],"answer":1,"explanation":"86 is between 80 and 90. The ones digit is 6, so round up to 90.","points":1},{"id":"Q9","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"What fraction of the circle is shaded?","diagram":{"type":"fraction_circle","params":{"parts":4,"shaded":3}},"options":["1/4","3/4","4/3","2/4"],"answer":1,"explanation":"3 of the 4 equal parts are shaded, so 3/4 is shaded.","points":1},{"id":"Q10","itemType":"single_choice","skill":"time","difficulty":"easy","passageId":null,"questionText":"What time does the clock show?","diagram":{"type":"clock","params":{"hour":4,"minute":15}},"options":["4:15","4:45","3:15","4:03"],"answer":0,"explanation":"The hour hand is just past 4, and the minute hand points to 3, which means 15 minutes. The time is 4:15.","points":1},{"id":"Q11","itemType":"equation","skill":"addition","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"▢ + 46 = 70","options":[],"answer":24,"explanation":"70 − 46 = 24, so 24 + 46 = 70.","points":1},{"id":"Q12","itemType":"single_choice","skill":"geometry","difficulty":"easy","passageId":null,"questionText":"How many sides does this pentagon have?","diagram":{"type":"shape","params":{"kind":"pentagon","sideLabels":["","","","",""]}},"options":["4","3","6","5"],"answer":3,"explanation":"A pentagon has 5 sides.","points":1},{"id":"Q13","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"What fraction of this bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":6,"shaded":2}},"options":["4/6","2/4","2/6","6/2"],"answer":2,"explanation":"2 of the 6 equal parts are shaded, so 2/6 is shaded.","points":1},{"id":"Q14","itemType":"single_choice","skill":"area","difficulty":"easy","passageId":null,"questionText":"What is the area of this rectangle?","diagram":{"type":"rectangle","params":{"width":5,"height":4,"unit":"cm","showGrid":true,"label":"Tile"}},"options":["9 square cm","18 square cm","16 square cm","20 square cm"],"answer":3,"explanation":"Area = width × height = 5 × 4 = 20 square cm.","points":1},{"id":"Q15","itemType":"single_choice","skill":"perimeter","difficulty":"easy","passageId":null,"questionText":"What is the perimeter of this rectangle?","diagram":{"type":"rectangle","params":{"width":8,"height":3,"unit":"cm","showGrid":false,"label":"Sign"}},"options":["22 cm","24 cm","16 cm","11 cm"],"answer":0,"explanation":"Perimeter = 8 + 3 + 8 + 3 = 22 cm.","points":1},{"id":"Q16","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"A class has 8 students. 3 of them wear glasses. What fraction of the class wears glasses?","diagram":null,"options":["3/5","5/8","8/3","3/8"],"answer":3,"explanation":"3 out of 8 students wear glasses, so 3/8 of the class wears glasses.","points":1},{"id":"Q17","itemType":"single_choice","skill":"subtraction","difficulty":"medium","passageId":null,"questionText":"A library had 600 books. Students borrowed 248 books. How many books are left?","diagram":null,"options":["362","452","352","348"],"answer":2,"explanation":"600 − 248 = 352 books left. Check: 352 + 248 = 600.","points":1},{"id":"Q18","itemType":"numeric_entry","skill":"multiplication","difficulty":"medium","passageId":null,"questionText":"There are 8 baskets. Each basket holds 6 apples. How many apples are there in all? Write only the number.","diagram":null,"options":[],"answer":48,"explanation":"8 × 6 = 48 apples.","points":1},{"id":"Q19","itemType":"equation","skill":"multiplication","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"▢ × 8 = 72","options":[],"answer":9,"explanation":"72 ÷ 8 = 9, so 9 × 8 = 72.","points":1},{"id":"Q20","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point show on the number line?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.25,"point":0.25,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["2/4","3/4","1/2","1/4"],"answer":3,"explanation":"The line from 0 to 1 is split into 4 equal parts. The point is at the 1st mark, which is 1/4.","points":1},{"id":"Q21","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Which fraction is equivalent to 1/2?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":2,"shaded":1,"label":"1/2"},{"parts":8,"shaded":4,"label":"?"}]}},"options":["3/8","4/8","5/8","2/8"],"answer":1,"explanation":"1/2 of a bar shades the same amount as 4/8 of an equal bar. So 1/2 = 4/8.","points":1},{"id":"Q22","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Which comparison is true?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":2,"shaded":1,"label":"1/2"},{"parts":6,"shaded":1,"label":"1/6"}]}},"options":["1/6 > 1/2","1/2 > 1/6","1/2 = 1/6","1/6 = 1/2"],"answer":1,"explanation":"When a whole is split into fewer parts, each part is bigger. Halves are bigger than sixths, so 1/2 > 1/6.","points":1},{"id":"Q23","itemType":"equation","skill":"subtraction","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"91 − ▢ = 58","options":[],"answer":33,"explanation":"91 − 58 = 33, so 91 − 33 = 58.","points":1},{"id":"Q24","itemType":"numeric_entry","skill":"area","difficulty":"medium","passageId":null,"questionText":"A rug is 7 ft wide and 6 ft long. What is its area, in square feet? Write only the number.","diagram":{"type":"rectangle","params":{"width":7,"height":6,"unit":"ft","showGrid":true,"label":"Rug"}},"options":[],"answer":42,"explanation":"Area = 7 × 6 = 42 square feet.","points":1},{"id":"Q25","itemType":"single_choice","skill":"data","difficulty":"medium","passageId":null,"questionText":"The bar graph shows books read by each student. How many more books did Tara read than Sam?","diagram":{"type":"bar_graph","params":{"title":"Books Read","xLabel":"Student","yLabel":"Books","yMax":20,"yStep":5,"bars":[{"label":"Sam","value":10},{"label":"Tara","value":18},{"label":"Liam","value":15}]}},"options":["8","5","28","6"],"answer":0,"explanation":"Tara read 18 and Sam read 10. 18 − 10 = 8 more books.","points":1},{"id":"Q26","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point show on the number line?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.3333333333333333,"point":0.6666666666666666,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["1/2","3/3","1/3","2/3"],"answer":3,"explanation":"The line from 0 to 1 is split into 3 equal parts. The point is at the 2nd mark, which is 2/3.","points":1},{"id":"Q27","itemType":"single_choice","skill":"elapsed_time","difficulty":"medium","passageId":null,"questionText":"Recess starts at 10:50 and lasts 25 minutes. What time does recess end?","diagram":{"type":"clock","params":{"hour":10,"minute":50}},"options":["11:25","11:05","11:15","11:10"],"answer":2,"explanation":"From 10:50 add 10 minutes to reach 11:00, then 15 more minutes makes 11:15. So 10:50 + 25 minutes = 11:15.","points":1},{"id":"Q28","itemType":"multi_select","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Select all fractions that equal a whole number (1).","diagram":{"type":"fraction_bar","params":{"parts":4,"shaded":4}},"options":["2/4","3/3","6/6","4/4"],"answer":[1,2,3],"explanation":"4/4, 3/3, and 6/6 each shade the whole, so each equals 1. But 2/4 only shades half, so it is not 1.","points":1},{"id":"Q29","itemType":"single_choice","skill":"multi_step_word_problem","difficulty":"hard","passageId":null,"questionText":"A teacher made 6 packs of pencils. Each pack had 9 pencils. She handed out 30 pencils. How many pencils are left?","diagram":null,"options":["54","24","15","33"],"answer":1,"explanation":"First find the total: 6 × 9 = 54 pencils. Then subtract: 54 − 30 = 24 pencils left.","points":1},{"id":"Q30","itemType":"numeric_entry","skill":"multi_step_word_problem","difficulty":"hard","passageId":null,"questionText":"Each comic book costs $7. Maya buys 4 comic books and pays with a $40 bill. How many dollars of change does she get back? Write only the number.","diagram":null,"options":[],"answer":12,"explanation":"4 comics × $7 = $28. Change: $40 − $28 = $12.","points":1},{"id":"Q31","itemType":"single_choice","skill":"area_perimeter","difficulty":"hard","passageId":null,"questionText":"A rectangle has a length of 9 cm and a width of 4 cm. Which statement is true about this rectangle?","diagram":{"type":"rectangle","params":{"width":9,"height":4,"unit":"cm","showGrid":true,"label":"Card"}},"options":["Its area is 36 square cm and its perimeter is 26 cm","Its area is 13 square cm and its perimeter is 26 cm","Its area is 36 square cm and its perimeter is 36 cm","Its area is 26 square cm and its perimeter is 36 cm"],"answer":0,"explanation":"Area = 9 × 4 = 36 square cm. Perimeter = 9 + 4 + 9 + 4 = 26 cm.","points":1},{"id":"Q32","itemType":"single_choice","skill":"fractions","difficulty":"hard","passageId":null,"questionText":"Ben ate 3/6 of a sandwich and Lily ate 1/2 of the same size sandwich. Who ate more?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":6,"shaded":3,"label":"Ben 3/6"},{"parts":2,"shaded":1,"label":"Lily 1/2"}]}},"options":["They ate the same amount","Lily ate more","You cannot tell","Ben ate more"],"answer":0,"explanation":"3/6 and 1/2 cover the same amount because 3/6 = 1/2. They ate the same amount.","points":1},{"id":"Q33","itemType":"numeric_entry","skill":"picture_graph","difficulty":"hard","passageId":null,"questionText":"In the picture graph, each star stands for 4 tickets sold. How many tickets did Grade 3 and Grade 4 sell together? Write only the number.","diagram":{"type":"picture_graph","params":{"title":"Tickets Sold","symbol":"⭐","unitValue":4,"rows":[{"label":"Grade 3","count":5},{"label":"Grade 4","count":3},{"label":"Grade 5","count":6}]}},"options":[],"answer":32,"explanation":"Grade 3: 5 × 4 = 20 tickets. Grade 4: 3 × 4 = 12 tickets. Together: 20 + 12 = 32 tickets.","points":1},{"id":"Q34","itemType":"single_choice","skill":"two_step","difficulty":"hard","passageId":null,"questionText":"A garden has 8 rows with 5 plants in each row. Then 4 plants die. Which expression shows the number of plants left?","diagram":null,"options":["8 × 5 × 4","8 + 5 − 4","8 × 5 − 4","(8 + 5) × 4"],"answer":2,"explanation":"Multiply rows by plants per row, then subtract the dead plants: 8 × 5 − 4 = 40 − 4 = 36.","points":1},{"id":"Q35","itemType":"equation","skill":"division","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"48 ÷ ▢ = 6","options":[],"answer":8,"explanation":"48 ÷ 6 = 8, so 48 ÷ 8 = 6.","points":1},{"id":"Q36","itemType":"equation","skill":"multiplication","difficulty":"hard","passageId":null,"questionText":"Fill in the blank to make the equation true.","diagram":null,"template":"7 × 6 = ▢ + 12","options":[],"answer":30,"explanation":"7 × 6 = 42. Then 42 − 12 = 30, so the box is 30 because 30 + 12 = 42.","points":1},{"id":"Q37","itemType":"multi_select","skill":"multiplication_facts","difficulty":"medium","passageId":null,"questionText":"Select all expressions that equal 24.","diagram":null,"options":["3 × 8","2 × 12","4 × 6","5 × 5"],"answer":[0,1,2],"explanation":"4 × 6 = 24, 3 × 8 = 24, and 2 × 12 = 24. But 5 × 5 = 25, not 24.","points":1},{"id":"Q38","itemType":"multi_select","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Select all fractions that are equal to 1/4.","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":4,"shaded":1,"label":"1/4"},{"parts":8,"shaded":2,"label":"2/8"},{"parts":12,"shaded":3,"label":"3/12"}]}},"options":["2/8","3/12","1/8","3/4"],"answer":[0,1],"explanation":"2/8 = 1/4 and 3/12 = 1/4. But 3/4 and 1/8 are not equal to 1/4.","points":1},{"id":"Q39","itemType":"multi_select","skill":"even_odd","difficulty":"hard","passageId":null,"questionText":"Select all numbers that are even.","diagram":null,"options":["95","56","71","38"],"answer":[1,3],"explanation":"A number is even if its ones digit is 0, 2, 4, 6, or 8. 38 and 56 are even. 71 and 95 are odd.","points":1},{"id":"Q40","itemType":"multi_select","skill":"fractions","difficulty":"hard","passageId":null,"questionText":"Select all fractions that are greater than 1/2.","diagram":null,"options":["2/3","1/4","5/8","3/4"],"answer":[0,2,3],"explanation":"3/4, 2/3, and 5/8 are each more than one half. But 1/4 is less than 1/2.","points":1}]}');
INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-math-eog-5',3,'math','eog','Grade 3 Math — EOG Practice Test 5',120,40,'curated','2026-06-02T00:00:00.000Z','{"id":"g3-math-eog-5","grade":3,"subject":"math","testType":"eog","title":"Grade 3 Math — EOG Practice Test 5","instructions":"Read each question carefully. Choose the best answer. For gridded questions, enter just the number. For fill-in-the-blank equations, enter the number that makes the equation true.","timeLimitMinutes":120,"calculatorAllowed":false,"source":"curated","passages":[],"questions":[{"id":"Q1","itemType":"single_choice","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"What multiplication fact does this array of dots show?","diagram":{"type":"array_dots","params":{"rows":4,"cols":7}},"options":["4 × 6 = 24","3 × 7 = 21","4 × 7 = 28","4 × 7 = 21"],"answer":2,"explanation":"There are 4 rows of 7 dots: 4 × 7 = 28.","points":1},{"id":"Q2","itemType":"single_choice","skill":"place_value","difficulty":"easy","passageId":null,"questionText":"Which number is shown by these base-ten blocks?","diagram":{"type":"base_ten","params":{"hundreds":4,"tens":2,"ones":0}},"options":["402","42","420","4200"],"answer":2,"explanation":"4 hundreds, 2 tens, and 0 ones make 420.","points":1},{"id":"Q3","itemType":"single_choice","skill":"rounding","difficulty":"easy","passageId":null,"questionText":"What is 67 rounded to the nearest ten?","diagram":null,"options":["60","65","70","100"],"answer":2,"explanation":"67 is closer to 70 than to 60, so it rounds to 70.","points":1},{"id":"Q4","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"What fraction of the circle is shaded?","diagram":{"type":"fraction_circle","params":{"parts":4,"shaded":3}},"options":["1/4","3/4","3/1","4/3"],"answer":1,"explanation":"3 of the 4 equal parts are shaded, so 3/4.","points":1},{"id":"Q5","itemType":"single_choice","skill":"time","difficulty":"easy","passageId":null,"questionText":"What time does the clock show?","diagram":{"type":"clock","params":{"hour":2,"minute":30}},"options":["3:30","6:10","2:30","2:06"],"answer":2,"explanation":"The hour hand is halfway between 2 and 3 and the minute hand points to 6, which is 30 minutes, so 2:30.","points":1},{"id":"Q6","itemType":"numeric_entry","skill":"addition","difficulty":"easy","passageId":null,"questionText":"What is 348 + 215? Enter just the number.","diagram":null,"options":[],"answer":563,"explanation":"348 + 215 = 563.","points":1},{"id":"Q7","itemType":"equation","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"6 × ▢ = 48","diagram":null,"options":[],"answer":8,"explanation":"48 ÷ 6 = 8.","points":1},{"id":"Q8","itemType":"single_choice","skill":"division","difficulty":"easy","passageId":null,"questionText":"What is 54 ÷ 9?","diagram":null,"options":["7","8","5","6"],"answer":3,"explanation":"9 × 6 = 54, so 54 ÷ 9 = 6.","points":1},{"id":"Q9","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"Which comparison is true?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":3,"shaded":2,"label":"2/3"},{"parts":3,"shaded":1,"label":"1/3"}]}},"options":["2/3 = 1/3","2/3 > 1/3","2/3 < 1/3","1/3 > 2/3"],"answer":1,"explanation":"2/3 has more shaded parts than 1/3, so 2/3 > 1/3.","points":1},{"id":"Q10","itemType":"single_choice","skill":"geometry","difficulty":"easy","passageId":null,"questionText":"How many sides does this shape have?","diagram":{"type":"shape","params":{"kind":"pentagon","sideLabels":["","","","",""]}},"options":["4","5","3","6"],"answer":1,"explanation":"A pentagon has 5 sides.","points":1},{"id":"Q11","itemType":"single_choice","skill":"bar_graph","difficulty":"easy","passageId":null,"questionText":"How many books did Mia read?","diagram":{"type":"bar_graph","params":{"title":"Books Read","xLabel":"Student","yLabel":"Books","yMax":12,"yStep":2,"bars":[{"label":"Leo","value":5},{"label":"Mia","value":8},{"label":"Tess","value":3}]}},"options":["8","3","12","5"],"answer":0,"explanation":"Mia''s bar reaches 8 on the scale.","points":1},{"id":"Q12","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.25,"point":0.75,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["2/4","3/4","1/4","1/2"],"answer":1,"explanation":"The number line is split into 4 equal parts and the point is at the third mark, which is 3/4.","points":1},{"id":"Q13","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"What fraction of this bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":6,"shaded":5}},"options":["1/6","6/5","5/6","5/1"],"answer":2,"explanation":"5 of the 6 equal parts are shaded, so 5/6.","points":1},{"id":"Q14","itemType":"equation","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"▢ × 8 = 48","diagram":null,"options":[],"answer":6,"explanation":"48 ÷ 8 = 6.","points":1},{"id":"Q15","itemType":"equation","skill":"addition","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"▢ + 46 = 73","diagram":null,"options":[],"answer":27,"explanation":"73 − 46 = 27.","points":1},{"id":"Q16","itemType":"numeric_entry","skill":"division","difficulty":"medium","passageId":null,"questionText":"A teacher shares 72 stickers equally among 8 students. How many stickers does each student get? Enter just the number.","diagram":null,"options":[],"answer":9,"explanation":"72 ÷ 8 = 9 stickers each.","points":1},{"id":"Q17","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Which fraction is equivalent to 1/3?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":3,"shaded":1,"label":"1/3"},{"parts":6,"shaded":2,"label":"?"}]}},"options":["1/6","4/6","3/6","2/6"],"answer":3,"explanation":"2/6 covers the same amount as 1/3, so they are equivalent.","points":1},{"id":"Q18","itemType":"single_choice","skill":"elapsed_time","difficulty":"medium","passageId":null,"questionText":"Music class starts at the time shown and lasts 25 minutes. What time does it end?","diagram":{"type":"clock","params":{"hour":10,"minute":15}},"options":["10:35","10:30","11:15","10:40"],"answer":3,"explanation":"10:15 plus 25 minutes is 10:40.","points":1},{"id":"Q19","itemType":"numeric_entry","skill":"area","difficulty":"medium","passageId":null,"questionText":"A rug is 8 feet long and 5 feet wide. What is its area, in square feet? Enter just the number.","diagram":{"type":"rectangle","params":{"width":8,"height":5,"unit":"ft","showGrid":true,"label":"Rug"}},"options":[],"answer":40,"explanation":"Area = 8 × 5 = 40 square feet.","points":1},{"id":"Q20","itemType":"single_choice","skill":"picture_graph","difficulty":"medium","passageId":null,"questionText":"Each apple stands for 5 pieces of fruit picked. How many pieces did Class B pick?","diagram":{"type":"picture_graph","params":{"title":"Fruit Picked","symbol":"🍎","unitValue":5,"rows":[{"label":"Class A","count":3},{"label":"Class B","count":7},{"label":"Class C","count":4}]}},"options":["30","7","35","12"],"answer":2,"explanation":"7 apples × 5 = 35 pieces of fruit.","points":1},{"id":"Q21","itemType":"equation","skill":"subtraction","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"432 − ▢ = 276","diagram":null,"options":[],"answer":156,"explanation":"432 − 276 = 156.","points":1},{"id":"Q22","itemType":"multi_select","skill":"geometry","difficulty":"medium","passageId":null,"questionText":"Select all the shapes that are quadrilaterals (shapes with exactly 4 sides).","diagram":{"type":"shape","params":{"kind":"square","sideLabels":["","","",""]}},"options":["Triangle","Square","Rhombus","Pentagon"],"answer":[1,2],"explanation":"A square and a rhombus each have exactly 4 sides. A pentagon has 5 sides and a triangle has 3.","points":1},{"id":"Q23","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Which comparison is true?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":6,"shaded":4,"label":"4/6"},{"parts":6,"shaded":3,"label":"3/6"}]}},"options":["4/6 > 3/6","4/6 < 3/6","4/6 = 3/6","3/6 > 4/6"],"answer":0,"explanation":"With the same denominator, more shaded parts means more: 4/6 > 3/6.","points":1},{"id":"Q24","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.25,"point":0.5,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["1/3","1/4","3/4","2/4"],"answer":3,"explanation":"The number line is split into 4 equal parts and the point is at the second mark, which is 2/4.","points":1},{"id":"Q25","itemType":"single_choice","skill":"fractions","difficulty":"medium","passageId":null,"questionText":"There are 8 fish in a tank. 3 of them are orange. What fraction of the fish are orange?","diagram":null,"options":["3/8","3/5","8/3","5/8"],"answer":0,"explanation":"3 out of 8 fish are orange, so 3/8.","points":1},{"id":"Q26","itemType":"numeric_entry","skill":"place_value","difficulty":"medium","passageId":null,"questionText":"What is the value of the digit 7 in the number 736? Enter just the number.","diagram":null,"options":[],"answer":700,"explanation":"The 7 is in the hundreds place, so its value is 700.","points":1},{"id":"Q27","itemType":"equation","skill":"subtraction","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"91 − ▢ = 64","diagram":null,"options":[],"answer":27,"explanation":"91 − 64 = 27.","points":1},{"id":"Q28","itemType":"single_choice","skill":"properties","difficulty":"medium","passageId":null,"questionText":"Which expression has the same value as 7 × 6?","diagram":null,"options":["6 × 7","6 + 6 + 6 + 6","7 + 7 + 7","7 + 6"],"answer":0,"explanation":"Multiplication can be done in any order, so 6 × 7 = 7 × 6 = 42.","points":1},{"id":"Q29","itemType":"multi_select","skill":"patterns","difficulty":"medium","passageId":null,"questionText":"In the counting pattern 4, 8, 12, 16, 20, ..., select all the numbers that belong in the pattern.","diagram":null,"options":["32","24","26","30"],"answer":[0,1],"explanation":"The pattern is multiples of 4. 24 and 32 are multiples of 4; 30 and 26 are not.","points":1},{"id":"Q30","itemType":"equation","skill":"division","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"56 ÷ ▢ = 7","diagram":null,"options":[],"answer":8,"explanation":"56 ÷ 8 = 7, so the blank is 8.","points":1},{"id":"Q31","itemType":"single_choice","skill":"multi_step_word_problem","difficulty":"hard","passageId":null,"questionText":"A gardener planted 4 rows of tulips with 9 tulips in each row. Then 12 tulips were picked. How many tulips are left?","diagram":null,"options":["48","24","36","25"],"answer":1,"explanation":"4 × 9 = 36 tulips; 36 − 12 = 24 tulips left.","points":1},{"id":"Q32","itemType":"single_choice","skill":"multi_step_word_problem","difficulty":"hard","passageId":null,"questionText":"Each ticket costs $7. Dana buys 5 tickets and pays with a $50 bill. How much change does she get back?","diagram":null,"options":["$35","$15","$45","$13"],"answer":1,"explanation":"5 × $7 = $35; $50 − $35 = $15 change.","points":1},{"id":"Q33","itemType":"numeric_entry","skill":"area","difficulty":"hard","passageId":null,"questionText":"A rectangle has an area of 56 square centimeters. If one side is 8 centimeters long, how long is the other side, in centimeters? Enter just the number.","diagram":null,"options":[],"answer":7,"explanation":"Area = length × width, so 56 ÷ 8 = 7 cm.","points":1},{"id":"Q34","itemType":"single_choice","skill":"perimeter","difficulty":"hard","passageId":null,"questionText":"What is the perimeter, in units, of this rectangle?","diagram":{"type":"rectangle","params":{"width":6,"height":4,"unit":"unit","showGrid":true,"label":"Garden"}},"options":["20 units","18 units","10 units","24 units"],"answer":0,"explanation":"Perimeter = 6 + 4 + 6 + 4 = 20 units. (Area would be 24, a common trap.)","points":1},{"id":"Q35","itemType":"single_choice","skill":"elapsed_time","difficulty":"hard","passageId":null,"questionText":"Recess started at 11:50 and ended at 12:20. How long did recess last?","diagram":null,"options":["70 minutes","20 minutes","40 minutes","30 minutes"],"answer":3,"explanation":"From 11:50 to 12:00 is 10 minutes, and 12:00 to 12:20 is 20 minutes: 10 + 20 = 30 minutes.","points":1},{"id":"Q36","itemType":"single_choice","skill":"fractions","difficulty":"hard","passageId":null,"questionText":"Which fraction is the greatest?","diagram":null,"options":["1/2","1/4","1/8","1/5"],"answer":0,"explanation":"When the top number is 1, the smaller the bottom number, the larger the fraction. 1/2 is the greatest because 2 is the smallest denominator.","points":1},{"id":"Q37","itemType":"multi_select","skill":"multiplication_facts","difficulty":"medium","passageId":null,"questionText":"Select all the expressions that equal 24.","diagram":null,"options":["3 × 8","4 × 6","5 × 5","2 × 12"],"answer":[0,1,3],"explanation":"4×6=24, 3×8=24, and 2×12=24. 5×5=25, so it is not correct.","points":1},{"id":"Q38","itemType":"multi_select","skill":"fractions","difficulty":"hard","passageId":null,"questionText":"Select all the fractions that are equal to 1/2.","diagram":null,"options":["3/6","4/8","2/5","2/4"],"answer":[0,1,3],"explanation":"3/6, 2/4, and 4/8 each equal 1/2. 2/5 is less than 1/2.","points":1},{"id":"Q39","itemType":"multi_select","skill":"rounding","difficulty":"hard","passageId":null,"questionText":"Select all the numbers that round to 600 when rounded to the nearest hundred.","diagram":null,"options":["548","552","647","649"],"answer":[1,2,3],"explanation":"552, 649, and 647 each round to 600. 548 rounds to 500.","points":1},{"id":"Q40","itemType":"numeric_entry","skill":"multi_step_word_problem","difficulty":"hard","passageId":null,"questionText":"A baker made 7 trays of muffins with 6 muffins on each tray. She sold 23 muffins. How many muffins are left? Enter just the number.","diagram":null,"options":[],"answer":19,"explanation":"7 × 6 = 42 muffins made; 42 − 23 = 19 left.","points":1}]}');
INSERT INTO "tests" ("id","grade","subject","test_type","title","time_limit_minutes","question_count","source","created_at","data") VALUES('g3-math-eog-6',3,'math','eog','Grade 3 Math — EOG Practice Test 6',120,40,'curated','2026-06-02T00:00:00.000Z','{"id":"g3-math-eog-6","grade":3,"subject":"math","testType":"eog","title":"Grade 3 Math — EOG Practice Test 6","instructions":"Read each question carefully. Choose the best answer. For gridded questions, enter just the number. For fill-in-the-blank equations, enter the number that makes the equation true.","timeLimitMinutes":120,"calculatorAllowed":false,"source":"curated","passages":[],"questions":[{"id":"Q1","itemType":"single_choice","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"What multiplication fact does this array of dots show?","diagram":{"type":"array_dots","params":{"rows":6,"cols":3}},"options":["6 × 2 = 12","5 × 3 = 15","6 × 3 = 18","6 × 3 = 21"],"answer":2,"explanation":"There are 6 rows of 3 dots: 6 × 3 = 18.","points":1},{"id":"Q2","itemType":"single_choice","skill":"place_value","difficulty":"easy","passageId":null,"questionText":"Which number is shown by these base-ten blocks?","diagram":{"type":"base_ten","params":{"hundreds":3,"tens":0,"ones":7}},"options":["37","307","3007","370"],"answer":1,"explanation":"3 hundreds, 0 tens, and 7 ones make 307.","points":1},{"id":"Q3","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"What fraction of this bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":4,"shaded":3}},"options":["4/3","2/4","1/4","3/4"],"answer":3,"explanation":"3 of the 4 equal parts are shaded, so 3/4.","points":1},{"id":"Q4","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"What fraction of the circle is shaded?","diagram":{"type":"fraction_circle","params":{"parts":6,"shaded":2}},"options":["6/2","4/6","2/6","1/6"],"answer":2,"explanation":"2 of the 6 equal parts are shaded, so 2/6.","points":1},{"id":"Q5","itemType":"single_choice","skill":"time","difficulty":"easy","passageId":null,"questionText":"What time does the clock show?","diagram":{"type":"clock","params":{"hour":7,"minute":45}},"options":["7:45","9:35","7:09","8:45"],"answer":0,"explanation":"The hour hand is between 7 and 8 and the minute hand points to 9, which is 45 minutes, so 7:45.","points":1},{"id":"Q6","itemType":"numeric_entry","skill":"subtraction","difficulty":"easy","passageId":null,"questionText":"What is 526 − 184? Enter just the number.","diagram":null,"options":[],"answer":342,"explanation":"526 − 184 = 342.","points":1},{"id":"Q7","itemType":"equation","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"9 × ▢ = 63","diagram":null,"options":[],"answer":7,"explanation":"63 ÷ 9 = 7.","points":1},{"id":"Q8","itemType":"single_choice","skill":"division","difficulty":"easy","passageId":null,"questionText":"What is 42 ÷ 6?","diagram":null,"options":["6","9","8","7"],"answer":3,"explanation":"6 × 7 = 42, so 42 ÷ 6 = 7.","points":1},{"id":"Q9","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"Which comparison is true?","diagram":{"type":"fraction_bar","params":{"bars":[{"parts":4,"shaded":1,"label":"1/4"},{"parts":4,"shaded":3,"label":"3/4"}]}},"options":["3/4 < 1/4","1/4 < 3/4","1/4 = 3/4","1/4 > 3/4"],"answer":1,"explanation":"1/4 has fewer shaded parts than 3/4, so 1/4 < 3/4.","points":1},{"id":"Q10","itemType":"single_choice","skill":"geometry","difficulty":"easy","passageId":null,"questionText":"How many sides does this shape have?","diagram":{"type":"shape","params":{"kind":"hexagon","sideLabels":["","","","","",""]}},"options":["7","8","5","6"],"answer":3,"explanation":"A hexagon has 6 sides.","points":1},{"id":"Q11","itemType":"single_choice","skill":"bar_graph","difficulty":"easy","passageId":null,"questionText":"How many cans did Ravi collect?","diagram":{"type":"bar_graph","params":{"title":"Cans Collected","xLabel":"Student","yLabel":"Cans","yMax":20,"yStep":5,"bars":[{"label":"Ravi","value":15},{"label":"Sam","value":10},{"label":"Joy","value":5}]}},"options":["15","5","20","10"],"answer":0,"explanation":"Ravi''s bar reaches 15 on the scale.","points":1},{"id":"Q12","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"Which fraction does the point on the number line show?","diagram":{"type":"number_line","params":{"min":0,"max":1,"step":0.3333,"point":0.3333,"marks":[{"value":0,"label":"0"},{"value":1,"label":"1"}]}},"options":["1/2","1/3","2/3","3/3"],"answer":1,"explanation":"The number line is split into 3 equal parts and the point is at the first mark, which is 1/3.","points":1},{"id":"Q13","itemType":"single_choice","skill":"fractions","difficulty":"easy","passageId":null,"questionText":"What fraction of this bar is shaded?","diagram":{"type":"fraction_bar","params":{"parts":8,"shaded":3}},"options":["8/3","3/8","5/8","1/8"],"answer":1,"explanation":"3 of the 8 equal parts are shaded, so 3/8.","points":1},{"id":"Q14","itemType":"equation","skill":"multiplication","difficulty":"easy","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"▢ × 4 = 36","diagram":null,"options":[],"answer":9,"explanation":"36 ÷ 4 = 9.","points":1},{"id":"Q15","itemType":"equation","skill":"addition","difficulty":"medium","passageId":null,"questionText":"Fill in the blank to make the equation true.","template":"▢ + 68 = 125","diagram":null,"options":[],"answer":57,"explanation":"125 − 68 = 57.","points":1},{"id":"Q16","itemType":"numeric_entry","skill":"division","difficulty":"medium","passageId":null,"questionText":"A baker puts 48 rolls equally into 6 baskets. How many rolls are in each basket? Enter just the number.","diagram":null,"options":[],"answer":8,"explanation":"48 ÷ 6 = 8 rolls 