INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('ribbon','noun','A long, thin piece of cloth used for tying or decoration.','She tied a ribbon in her hair for the party.','RIB-un','2026-06-03T03:39:49.270Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('phrase','noun','A group of words that have a special meaning.','The phrase ''time flies'' means that time goes by quickly.','frayz','2026-06-03T21:01:37.132Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('meaning','noun','It tells us what something is or what it means.','The meaning of the word ''happy'' is feeling good.','MEE-ning','2026-06-03T21:01:49.257Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('nina','noun','Nina is a girl''s name.','Nina loves to make pottery with her grandma.','NEE-nah','2026-06-04T00:22:58.869Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('theo','noun','Theo is a name for a boy or a friend.','Theo helped me with my homework today.','THEE-oh','2026-06-04T00:23:16.478Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('crooked','adjective','Not straight; bent or leaning to one side.','Nina''s pots were crooked and didn''t stand up straight.','KROO-kid','2026-06-04T00:27:18.806Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('lopsided','adjective','It is not even or balanced on both sides.','The lopsided pot spilled water on one side.','lop-SIDE-ed','2026-06-04T00:30:52.586Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('precipitation','noun','Precipitation is water that falls from the sky, like rain or snow.','Yesterday, the precipitation made the ground wet and muddy.','pre-sip-i-TA-tion','2026-06-04T01:07:12.769Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('condensation','noun','Condensation is when water vapor turns into tiny water drops.','I saw condensation on the cold glass after my drink was poured.','kon-den-SAY-shun','2026-06-04T01:07:19.343Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('sailors','noun','Sailors are people who work on ships at sea.','The sailors waved goodbye as their ship left the harbor.','SAY-lers','2026-06-04T01:12:10.778Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('hooves','noun','Hooves are the hard feet of some animals like horses and goats.','The horse ran fast on its strong hooves.','hoovz','2026-06-04T11:03:25.610Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('streak','noun','A streak is a line or mark that is different.','Pepper had a stubborn streak that made her hard to lead.','stree-k','2026-06-04T19:57:10.927Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('scratching','verb','Using your nails to rub your skin.','I was scratching my arm because it was itchy.','SKRATCH-ing','2026-06-04T20:03:08.059Z');
INSERT INTO "glossary" ("word","part_of_speech","meaning","example","phonetic","created_at") VALUES('sleeves','noun','Sleeves are the parts of a shirt that cover your arms.','My shirt has long sleeves to keep my arms warm.','slee-vz','2026-06-04T20:03:44.690Z');
INSERT INTO "explanations" ("qkey","strategy","created_at") VALUES('x1mq5g5e','Think of 6 bags of 8 apples as 6 groups of 10 apples, which is 60. Then, subtract the 12 apples you counted extra (2 from each bag). So, 60 - 12 = 48 apples total!','2026-06-03T11:20:34.600Z');
